{
  "name": "EcoSnap",
  "description": "An AI-powered recycling assistant that identifies waste items, awards points, and encourages eco-friendly habits through a competitive leaderboard.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface RecycleItem {
  id: string;
  name: string;
  category: string;
  isRecyclable: boolean;
  points: number;
  timestamp: number;
  imageUrl?: string;
  explanation: string;
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  totalPoints: number;
  itemsRecycled: number;
  rank: number;
  badges: string[];
}

export interface AnalysisResult {
  itemName: string;
  materialCategory: string;
  isRecyclable: boolean;
  reasoning: string;
  estimatedPoints: number;
  funFact?: string;
}

export enum ViewState {
  SCANNER = 'SCANNER',
  LEADERBOARD = 'LEADERBOARD',
  PROFILE = 'PROFILE',
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeImage = async (base64Image: string): Promise<AnalysisResult> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          {
            text: `Analyze this image to identify the main object for recycling purposes.
            Provide a strict JSON response.
            Determine if it is recyclable, what material it is, and assign a point value (10-100) based on difficulty/impact.
            If it is not recyclable, set points to 0.
            Also provide a short explanation and a fun fact.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            itemName: { type: Type.STRING },
            materialCategory: { type: Type.STRING, enum: ["Plastic", "Paper", "Glass", "Metal", "Organic", "E-Waste", "Textile", "Other"] },
            isRecyclable: { type: Type.BOOLEAN },
            reasoning: { type: Type.STRING },
            estimatedPoints: { type: Type.INTEGER },
            funFact: { type: Type.STRING }
          },
          required: ["itemName", "materialCategory", "isRecyclable", "reasoning", "estimatedPoints", "funFact"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text from Gemini");

    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    // Fallback for demo purposes if API fails or quota exceeded, though in prod we'd handle error UI
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Camera, Upload, CheckCircle, XCircle, Loader2, Info, ArrowRight } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult, RecycleItem } from '../types';

interface ScannerProps {
  onScanComplete: (item: RecycleItem) => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onScanComplete }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    setResult(null);
    setIsAnalyzing(true);

    // Create preview
    const objectUrl = URL.createObjectURL(file);
    setPreviewUrl(objectUrl);

    try {
      // Convert to base64
      const base64Promise = new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            // Remove data:image/...;base64, prefix
            const base64 = result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = error => reject(error);
      });

      const base64Data = await base64Promise;
      const analysis = await analyzeImage(base64Data);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      setError("Failed to analyze image. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleConfirm = () => {
    if (result && previewUrl) {
      const newItem: RecycleItem = {
        id: Date.now().toString(),
        name: result.itemName,
        category: result.materialCategory,
        isRecyclable: result.isRecyclable,
        points: result.estimatedPoints,
        timestamp: Date.now(),
        imageUrl: previewUrl,
        explanation: result.reasoning
      };
      onScanComplete(newItem);
      // Reset
      setResult(null);
      setPreviewUrl(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleRetake = () => {
    setResult(null);
    setPreviewUrl(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4">
      {/* Header */}
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-emerald-800">Scan Item</h2>
        <p className="text-emerald-600">Identify rubbish & earn points</p>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center space-y-6">

        {/* Empty State / Upload Button */}
        {!previewUrl && (
          <div className="w-full flex flex-col items-center space-y-6">
            <div className="relative group cursor-pointer">
              <div className="absolute -inset-1 bg-gradient-to-r from-emerald-400 to-cyan-400 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-200"></div>
              <label 
                htmlFor="camera-input" 
                className="relative flex items-center justify-center w-48 h-48 bg-white rounded-full shadow-xl border-4 border-emerald-50 cursor-pointer active:scale-95 transition-transform duration-200"
              >
                <div className="flex flex-col items-center space-y-2">
                  <Camera className="w-12 h-12 text-emerald-500" />
                  <span className="text-sm font-semibold text-gray-500">Tap to Snap</span>
                </div>
              </label>
              <input 
                ref={fileInputRef}
                id="camera-input" 
                type="file" 
                accept="image/*" 
                capture="environment" 
                className="hidden" 
                onChange={handleFileChange}
              />
            </div>
            <p className="text-xs text-gray-400 max-w-xs text-center">
              Works best with clear lighting. Identify plastic, glass, paper, and metal instantly.
            </p>
          </div>
        )}

        {/* Loading State */}
        {isAnalyzing && previewUrl && (
          <div className="flex flex-col items-center space-y-4 animate-in fade-in duration-300">
            <div className="relative w-64 h-64 rounded-2xl overflow-hidden shadow-lg border-4 border-white">
              <img src={previewUrl} alt="Analyzing" className="w-full h-full object-cover blur-sm" />
              <div className="absolute inset-0 flex items-center justify-center bg-black/30">
                <Loader2 className="w-12 h-12 text-white animate-spin" />
              </div>
            </div>
            <p className="text-emerald-700 font-medium animate-pulse">Analyzing composition...</p>
          </div>
        )}

        {/* Result State */}
        {!isAnalyzing && result && previewUrl && (
          <div className="w-full animate-in slide-in-from-bottom-8 duration-500">
            <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-emerald-100">
              <div className="relative h-48">
                <img src={previewUrl} alt="Scanned" className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent flex flex-col justify-end p-4">
                   <h3 className="text-white text-2xl font-bold capitalize">{result.itemName}</h3>
                   <span className="text-emerald-200 font-medium text-sm">{result.materialCategory}</span>
                </div>
              </div>

              <div className="p-6 space-y-4">
                <div className="flex items-center justify-between">
                  <div className={`flex items-center space-x-2 px-4 py-2 rounded-full ${result.isRecyclable ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                    {result.isRecyclable ? <CheckCircle size={20} /> : <XCircle size={20} />}
                    <span className="font-bold">{result.isRecyclable ? 'Recyclable' : 'Not Recyclable'}</span>
                  </div>
                  {result.isRecyclable && (
                    <div className="text-right">
                      <span className="block text-xs text-gray-400 uppercase tracking-wider">Points</span>
                      <span className="text-2xl font-black text-emerald-600">+{result.estimatedPoints}</span>
                    </div>
                  )}
                </div>

                <div className="bg-gray-50 p-4 rounded-xl text-sm text-gray-600 leading-relaxed">
                  <p>{result.reasoning}</p>
                </div>

                {result.funFact && (
                   <div className="flex items-start space-x-2 text-xs text-sky-600 bg-sky-50 p-3 rounded-lg">
                      <Info className="w-4 h-4 mt-0.5 flex-shrink-0" />
                      <p>{result.funFact}</p>
                   </div>
                )}

                <div className="flex space-x-3 pt-2">
                  <button 
                    onClick={handleRetake}
                    className="flex-1 py-3 rounded-xl border border-gray-200 text-gray-600 font-semibold hover:bg-gray-50 transition"
                  >
                    Retake
                  </button>
                  <button 
                    onClick={handleConfirm}
                    className="flex-1 py-3 rounded-xl bg-emerald-500 text-white font-semibold shadow-lg shadow-emerald-200 hover:bg-emerald-600 transition flex items-center justify-center space-x-2"
                  >
                    <span>{result.isRecyclable ? 'Recycle & Collect' : 'Confirm'}</span>
                    <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Error State */}
        {error && (
            <div className="p-4 bg-red-50 text-red-600 rounded-xl text-center w-full">
                <p>{error}</p>
                <button onClick={handleRetake} className="mt-2 text-sm underline font-semibold">Try Again</button>
            </div>
        )}

      </div>
    </div>
  );
};

import React from 'react';
import { User } from '../types';
import { Trophy, Medal, Crown } from 'lucide-react';

interface LeaderboardProps {
  users: User[];
  currentUser: User;
}

export const Leaderboard: React.FC<LeaderboardProps> = ({ users, currentUser }) => {
  // Sort users by points
  const sortedUsers = [...users].sort((a, b) => b.totalPoints - a.totalPoints);

  const getRankIcon = (index: number) => {
    switch (index) {
      case 0: return <Crown className="w-6 h-6 text-yellow-500 fill-yellow-500" />;
      case 1: return <Medal className="w-6 h-6 text-gray-400 fill-gray-400" />;
      case 2: return <Medal className="w-6 h-6 text-amber-600 fill-amber-600" />;
      default: return <span className="text-gray-400 font-bold w-6 text-center">{index + 1}</span>;
    }
  };

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4">
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-emerald-800">Top Recyclers</h2>
        <p className="text-emerald-600">Local Heroes of the Week</p>
      </div>

      <div className="bg-gradient-to-br from-emerald-500 to-teal-600 rounded-2xl p-6 text-white shadow-lg mb-6 relative overflow-hidden">
        <div className="relative z-10 flex items-center justify-between">
           <div>
             <p className="text-emerald-100 text-sm font-medium mb-1">Your Rank</p>
             <div className="flex items-baseline space-x-2">
               <span className="text-4xl font-bold">#{sortedUsers.findIndex(u => u.id === currentUser.id) + 1}</span>
               <span className="text-emerald-100">of {sortedUsers.length}</span>
             </div>
           </div>
           <div className="text-right">
              <p className="text-emerald-100 text-sm font-medium mb-1">Your Score</p>
              <span className="text-3xl font-bold">{currentUser.totalPoints}</span>
           </div>
        </div>
        <Trophy className="absolute -bottom-4 -right-4 w-32 h-32 text-emerald-400 opacity-20 rotate-12" />
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar space-y-3 pb-20">
        {sortedUsers.map((user, index) => (
          <div 
            key={user.id}
            className={`flex items-center p-4 rounded-xl border transition-all ${
              user.id === currentUser.id 
              ? 'bg-emerald-50 border-emerald-200 shadow-sm' 
              : 'bg-white border-gray-100'
            }`}
          >
            <div className="flex-shrink-0 mr-4 flex items-center justify-center w-8">
              {getRankIcon(index)}
            </div>

            <div className="relative mr-4">
                <img src={user.avatar} alt={user.name} className="w-12 h-12 rounded-full object-cover border-2 border-white shadow-sm" />
                {index === 0 && <div className="absolute -top-1 -right-1 bg-yellow-400 w-4 h-4 rounded-full border-2 border-white" />}
            </div>

            <div className="flex-1">
              <h3 className={`font-semibold ${user.id === currentUser.id ? 'text-emerald-900' : 'text-gray-800'}`}>
                {user.name} {user.id === currentUser.id && '(You)'}
              </h3>
              <p className="text-xs text-gray-500">{user.itemsRecycled} items recycled</p>
            </div>

            <div className="text-right">
              <span className="block font-bold text-emerald-600">{user.totalPoints}</span>
              <span className="text-[10px] text-gray-400 uppercase">pts</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { RecycleItem, User } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from 'recharts';
import { Leaf, History, TrendingUp } from 'lucide-react';

interface DashboardProps {
  user: User;
  history: RecycleItem[];
}

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#6366f1', '#ef4444'];

export const Dashboard: React.FC<DashboardProps> = ({ user, history }) => {

  // Prepare data for Pie Chart (Distribution by Category)
  const categoryCount = history.reduce((acc, item) => {
    if (item.isRecyclable) {
      acc[item.category] = (acc[item.category] || 0) + 1;
    }
    return acc;
  }, {} as Record<string, number>);

  const pieData = Object.keys(categoryCount).map((key) => ({
    name: key,
    value: categoryCount[key]
  }));

  // Prepare data for Bar Chart (Points over time - simplified to last 5 items)
  const recentHistory = [...history].reverse().slice(0, 5).reverse();
  const barData = recentHistory.map((item, index) => ({
    name: `Item ${index + 1}`,
    points: item.points
  }));

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4 overflow-y-auto no-scrollbar pb-24">
       <div className="mb-6">
        <h2 className="text-2xl font-bold text-emerald-800">Your Impact</h2>
        <p className="text-emerald-600">Tracking your eco-footprint</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 gap-4 mb-6">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-emerald-50">
          <div className="flex items-center space-x-2 mb-2">
            <div className="p-2 bg-emerald-100 rounded-lg">
              <Leaf className="w-5 h-5 text-emerald-600" />
            </div>
            <span className="text-xs font-semibold text-gray-500 uppercase">Total Items</span>
          </div>
          <p className="text-3xl font-bold text-gray-800">{user.itemsRecycled}</p>
        </div>
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-emerald-50">
          <div className="flex items-center space-x-2 mb-2">
            <div className="p-2 bg-sky-100 rounded-lg">
              <TrendingUp className="w-5 h-5 text-sky-600" />
            </div>
            <span className="text-xs font-semibold text-gray-500 uppercase">Avg Points</span>
          </div>
          <p className="text-3xl font-bold text-gray-800">
            {user.itemsRecycled > 0 ? Math.round(user.totalPoints / user.itemsRecycled) : 0}
          </p>
        </div>
      </div>

      {/* Charts Section */}
      {pieData.length > 0 ? (
        <>
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 mb-6">
            <h3 className="font-semibold text-gray-700 mb-4">Material Breakdown</h3>
            <div className="h-48 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    innerRadius={40}
                    outerRadius={70}
                    fill="#8884d8"
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {pieData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="flex flex-wrap gap-2 justify-center mt-2">
              {pieData.map((entry, index) => (
                <div key={entry.name} className="flex items-center space-x-1 text-xs text-gray-500">
                  <span className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }}></span>
                  <span>{entry.name}</span>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 mb-6">
            <h3 className="font-semibold text-gray-700 mb-4">Recent Points</h3>
             <div className="h-40 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={barData}>
                  <XAxis dataKey="name" hide />
                  <YAxis hide />
                  <Tooltip 
                    cursor={{fill: '#f3f4f6'}}
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                  <Bar dataKey="points" fill="#10b981" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
             </div>
          </div>
        </>
      ) : (
        <div className="bg-white p-8 rounded-2xl text-center border border-dashed border-gray-300 mb-6">
          <p className="text-gray-400">Scan your first item to see stats!</p>
        </div>
      )}

      {/* Recent History List */}
      <div className="space-y-4">
        <h3 className="font-semibold text-gray-700 flex items-center space-x-2">
          <History className="w-4 h-4" />
          <span>Recent Activity</span>
        </h3>
        {history.slice().reverse().map((item) => (
          <div key={item.id} className="flex items-center bg-white p-3 rounded-xl border border-gray-100 shadow-sm">
            <div className="h-12 w-12 rounded-lg bg-gray-100 overflow-hidden mr-3 flex-shrink-0">
               {item.imageUrl ? (
                   <img src={item.imageUrl} alt={item.name} className="h-full w-full object-cover" />
               ) : (
                   <div className="h-full w-full flex items-center justify-center text-gray-400">?</div>
               )}
            </div>
            <div className="flex-1">
              <h4 className="font-medium text-gray-800 capitalize">{item.name}</h4>
              <p className="text-xs text-gray-500">{new Date(item.timestamp).toLocaleDateString()}</p>
            </div>
            <span className={`font-bold ${item.isRecyclable ? 'text-emerald-600' : 'text-gray-400'}`}>
               {item.isRecyclable ? `+${item.points}` : '0'}
            </span>
          </div>
        ))}
         {history.length === 0 && (
            <p className="text-center text-sm text-gray-400 py-4">No recent history.</p>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { User, RecycleItem, ViewState } from './types';
import { Scan, BarChart2, User as UserIcon } from 'lucide-react';

// Mock Initial Data
const INITIAL_USERS: User[] = [
  { id: '1', name: 'Alice', avatar: 'https://picsum.photos/100/100?random=1', totalPoints: 1250, itemsRecycled: 45, rank: 1, badges: ['Eco-Warrior'] },
  { id: '2', name: 'Bob', avatar: 'https://picsum.photos/100/100?random=2', totalPoints: 980, itemsRecycled: 32, rank: 2, badges: [] },
  { id: '3', name: 'Charlie', avatar: 'https://picsum.photos/100/100?random=3', totalPoints: 850, itemsRecycled: 28, rank: 3, badges: [] },
  { id: 'me', name: 'You', avatar: 'https://picsum.photos/100/100?random=4', totalPoints: 0, itemsRecycled: 0, rank: 4, badges: [] },
];

export default function App() {
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User>(INITIAL_USERS[3]);
  const [history, setHistory] = useState<RecycleItem[]>([]);

  // Update current user in the users array whenever currentUser changes
  useEffect(() => {
    setUsers(prevUsers => prevUsers.map(u => u.id === 'me' ? currentUser : u));
  }, [currentUser]);

  const handleScanComplete = (item: RecycleItem) => {
    // Add to history
    setHistory(prev => [...prev, item]);

    // Update User Stats
    if (item.isRecyclable) {
      setCurrentUser(prev => ({
        ...prev,
        totalPoints: prev.totalPoints + item.points,
        itemsRecycled: prev.itemsRecycled + 1
      }));
    }
  };

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} history={history} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-gray-100 pb-safe shadow-[0_-5px_15px_rgba(0,0,0,0.02)]">
        <div className="flex justify-around items-center h-16 max-w-md mx-auto px-2">

          <button 
            onClick={() => setView(ViewState.LEADERBOARD)}
            className={`flex flex-col items-center justify-center w-16 h-full space-y-1 transition-colors ${view === ViewState.LEADERBOARD ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <BarChart2 className={`w-6 h-6 ${view === ViewState.LEADERBOARD ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Rank</span>
          </button>

          <button 
            onClick={() => setView(ViewState.SCANNER)}
            className="flex flex-col items-center justify-center -mt-6"
          >
             <div className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-transform duration-200 ${view === ViewState.SCANNER ? 'bg-emerald-500 scale-110 shadow-emerald-200' : 'bg-gray-800 hover:scale-105'}`}>
               <Scan className="w-7 h-7 text-white" />
             </div>
             <span className={`text-[10px] font-medium mt-1 ${view === ViewState.SCANNER ? 'text-emerald-600' : 'text-gray-400'}`}>Scan</span>
