import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, CheckCircle, XCircle, Loader2, Info, ArrowRight, MapPin } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult, RecycleItem } from '../types';

interface ScannerProps {
  onScanComplete: (item: RecycleItem) => void;
}

export const Scanner: React.FC<ScannerProps> = ({ onScanComplete }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [location, setLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  const [gettingLocation, setGettingLocation] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Attempt to get location quietly when component mounts to be ready
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
        },
        (err) => console.log("Location pre-fetch failed/denied", err),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  }, []);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    setResult(null);
    setIsAnalyzing(true);

    // Refresh location on new scan
    if (navigator.geolocation) {
       setGettingLocation(true);
       navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
          setGettingLocation(false);
        },
        () => setGettingLocation(false),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }

    // Create preview
    const objectUrl = URL.createObjectURL(file);
    setPreviewUrl(objectUrl);

    try {
      // Convert to base64
      const base64Promise = new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            // Remove data:image/...;base64, prefix
            const base64 = result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = error => reject(error);
      });

      const base64Data = await base64Promise;
      const analysis = await analyzeImage(base64Data);
      setResult(analysis);
    } catch (err) {
      console.error(err);
      setError("Failed to analyze image. Please try again.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleConfirm = () => {
    if (result && previewUrl) {
      const newItem: RecycleItem = {
        id: Date.now().toString(),
        name: result.itemName,
        category: result.materialCategory,
        isRecyclable: result.isRecyclable,
        points: result.estimatedPoints,
        timestamp: Date.now(),
        imageUrl: previewUrl,
        explanation: result.reasoning,
        location: location
      };
      onScanComplete(newItem);
      // Reset
      setResult(null);
      setPreviewUrl(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleRetake = () => {
    setResult(null);
    setPreviewUrl(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4">
      {/* Header */}
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-emerald-800">Scan Item</h2>
        <p className="text-emerald-600">Identify rubbish & earn points</p>
      </div>

      <div className="flex-1 flex flex-col items-center justify-center space-y-6">

        {/* Empty State / Upload Button */}
        {!previewUrl && (
          <div className="w-full flex flex-col items-center space-y-6">
            <div className="relative group cursor-pointer">
              <div className="absolute -inset-1 bg-gradient-to-r from-emerald-400 to-cyan-400 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-200"></div>
              <label 
                htmlFor="camera-input" 
                className="relative flex items-center justify-center w-48 h-48 bg-white rounded-full shadow-xl border-4 border-emerald-50 cursor-pointer active:scale-95 transition-transform duration-200"
              >
                <div className="flex flex-col items-center space-y-2">
                  <Camera className="w-12 h-12 text-emerald-500" />
                  <span className="text-sm font-semibold text-gray-500">Tap to Snap</span>
                </div>
              </label>
              <input 
                ref={fileInputRef}
                id="camera-input" 
                type="file" 
                accept="image/*" 
                capture="environment" 
                className="hidden" 
                onChange={handleFileChange}
              />
            </div>
            <p className="text-xs text-gray-400 max-w-xs text-center">
              Works best with clear lighting. Identify plastic, glass, paper, and metal instantly.
            </p>
          </div>
        )}

        {/* Loading State */}
        {isAnalyzing && previewUrl && (
          <div className="flex flex-col items-center space-y-4 animate-in fade-in duration-300">
            <div className="relative w-64 h-64 rounded-2xl overflow-hidden shadow-lg border-4 border-white">
              <img src={previewUrl} alt="Analyzing" className="w-full h-full object-cover blur-sm" />
              <div className="absolute inset-0 flex items-center justify-center bg-black/30">
