import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { RecycleItem } from '../types';
import { MapPin } from 'lucide-react';

interface InteractiveMapProps {
  items: RecycleItem[];
}

export const InteractiveMap: React.FC<InteractiveMapProps> = ({ items }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

  useEffect(() => {
    if (!mapContainerRef.current) return;

    // Initialize map if not already done
    if (!mapInstanceRef.current) {
      // Default view (approx center of world or user location later)
      // We will try to center on the most recent item or a default
      const defaultCenter: [number, number] = [40.7128, -74.0060]; // NYC default

      mapInstanceRef.current = L.map(mapContainerRef.current, {
        zoomControl: false,
        attributionControl: false
      }).setView(defaultCenter, 13);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
        subdomains: 'abcd',
        maxZoom: 20
      }).addTo(mapInstanceRef.current);

      // Add zoom control bottom right
      L.control.zoom({
        position: 'bottomright'
      }).addTo(mapInstanceRef.current);
    }

    const map = mapInstanceRef.current;

    // Clear existing markers (simplistic approach for this demo)
    map.eachLayer((layer) => {
      if (layer instanceof L.Marker) {
        map.removeLayer(layer);
      }
    });

    // Filter items with location
    const validItems = items.filter(item => item.location);
    const bounds = L.latLngBounds([]);

    // Add markers
    validItems.forEach(item => {
      if (!item.location) return;

      const { lat, lng } = item.location;

      // Create a custom div icon using HTML string
      const iconHtml = `
        <div class="relative flex items-center justify-center w-8 h-8">
           <div class="absolute w-8 h-8 bg-emerald-500 rounded-full opacity-30 animate-ping"></div>
           <div class="relative w-8 h-8 bg-white rounded-full border-2 border-emerald-500 shadow-lg flex items-center justify-center text-emerald-600 font-bold text-xs">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-leaf"><path d="M11 20A7 7 0 0 1 9.8 6.1C15.5 5 17 4.48 19 2c1 2 2 4.18 2 8 0 5.5-4.77 10-10 10Z"/><path d="M2 21c0-3 1.85-5.36 5.08-6C9.5 14.52 12 13 13 12"/></svg>
           </div>
        </div>
      `;

      const customIcon = L.divIcon({
        className: 'bg-transparent border-none',
        html: iconHtml,
        iconSize: [32, 32],
        iconAnchor: [16, 16],
        popupAnchor: [0, -16]
      });

      const marker = L.marker([lat, lng], { icon: customIcon }).addTo(map);

      const popupContent = `
        <div class="p-2 min-w-[150px] text-center">
