    if (validItems.length > 0) {
      map.fitBounds(bounds, { padding: [50, 50], maxZoom: 16 });
    } else {
       map.locate({ setView: true, maxZoom: 15 });
    }

    // Cleanup function not strictly necessary for single page app singleton but good practice
    return () => {
      // We keep the map instance alive for performance in this specific view switching architecture
    };
  }, [items]);

  return (
    <div className="flex flex-col h-full relative">
       {/* Map Overlay Header */}
       <div className="absolute top-4 left-0 right-0 z-10 flex justify-center pointer-events-none">
          <div className="bg-white/90 backdrop-blur-md shadow-sm border border-emerald-100 px-4 py-2 rounded-full pointer-events-auto">
             <div className="flex items-center space-x-2">
                <MapPin className="w-4 h-4 text-emerald-600" />
                <span className="text-sm font-semibold text-emerald-900">Eco Map</span>
                <span className="text-xs text-gray-400 border-l border-gray-300 pl-2 ml-2">
                  {items.filter(i => i.location).length} spots found
                </span>
             </div>
          </div>
       </div>

       <div ref={mapContainerRef} className="flex-1 w-full bg-slate-100" />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { User, RecycleItem, ViewState } from './types';
import { Scan, BarChart2, User as UserIcon, Map as MapIcon } from 'lucide-react';

// Start with an empty user list
const INITIAL_USERS: User[] = [];

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [history, setHistory] = useState<RecycleItem[]>([]);

  // Update users list when current user changes (e.g. after login or point update)
  useEffect(() => {
    if (currentUser) {
      setUsers(prevUsers => {
        // Remove previous instance of current user if exists
        const otherUsers = prevUsers.filter(u => u.id !== currentUser.id);
        return [...otherUsers, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setHistory([]);
    setUsers([]); // Clear users on logout so next login starts fresh
    setView(ViewState.SCANNER);
  };

  const handleScanComplete = (item: RecycleItem) => {
    if (!currentUser) return;

    // Add to history
    setHistory(prev => [...prev, item]);

    // Update User Stats
    if (item.isRecyclable) {
      setCurrentUser(prev => prev ? ({
        ...prev,
        totalPoints: prev.totalPoints + item.points,
        itemsRecycled: prev.itemsRecycled + 1
      }) : null);
    }
  };

  // If not authenticated, show Login screen
  if (!isAuthenticated || !currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} history={history} onLogout={handleLogout} />;
      case ViewState.MAP:
        return <InteractiveMap items={history} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-gray-100 pb-safe shadow-[0_-5px_15px_rgba(0,0,0,0.02)]">
        <div className="flex justify-around items-center h-16 max-w-md mx-auto px-2">

          <button 
            onClick={() => setView(ViewState.LEADERBOARD)}
            className={`flex flex-col items-center justify-center w-14 h-full space-y-1 transition-colors ${view === ViewState.LEADERBOARD ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <BarChart2 className={`w-6 h-6 ${view === ViewState.LEADERBOARD ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Rank</span>
          </button>

          <button 
            onClick={() => setView(ViewState.MAP)}
            className={`flex flex-col items-center justify-center w-14 h-full space-y-1 transition-colors ${view === ViewState.MAP ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <MapIcon className={`w-6 h-6 ${view === ViewState.MAP ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Map</span>
          </button>

          <button 
            onClick={() => setView(ViewState.SCANNER)}
            className="flex flex-col items-center justify-center -mt-6"
          >
             <div className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-transform duration-200 ${view === ViewState.SCANNER ? 'bg-emerald-500 scale-110 shadow-emerald-200' : 'bg-gray-800 hover:scale-105'}`}>
               <Scan className="w-7 h-7 text-white" />
             </div>
             <span className={`text-[10px] font-medium mt-1 ${view === ViewState.SCANNER ? 'text-emerald-600' : 'text-gray-400'}`}>Scan</span>
          </button>

          <button 
             onClick={() => setView(ViewState.PROFILE)}
             className={`flex flex-col items-center justify-center w-14 h-full space-y-1 transition-colors ${view === ViewState.PROFILE ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <UserIcon className={`w-6 h-6 ${view === ViewState.PROFILE ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Profile</span>
          </button>

        </div>
      </nav>
    </div>
  );
}

