import { Scan, BarChart2, User as UserIcon, Map as MapIcon } from 'lucide-react';

// Start with an empty user list
const INITIAL_USERS: User[] = [];

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [history, setHistory] = useState<RecycleItem[]>([]);

  // Update users list when current user changes (e.g. after login or point update)
  useEffect(() => {
    if (currentUser) {
      setUsers(prevUsers => {
        // Remove previous instance of current user if exists
        const otherUsers = prevUsers.filter(u => u.id !== currentUser.id);
        return [...otherUsers, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setHistory([]);
    setUsers([]); // Clear users on logout so next login starts fresh
    setView(ViewState.SCANNER);
  };

  const handleScanComplete = (item: RecycleItem) => {
    if (!currentUser) return;

    // Security Check: Prevent duplicate uploads
    if (item.imageSignature) {
      const isDuplicate = history.some(historyItem => historyItem.imageSignature === item.imageSignature);
      if (isDuplicate) {
        // Alert the administrator (simulated via console)
        console.error(`[ADMIN ALERT] User ${currentUser.name} (ID: ${currentUser.id}) attempted to upload a duplicate image. Signature: ${item.imageSignature}`);

        // Alert the user
        alert("⚠️ Duplicate Image Detected!\n\nThis image has already been submitted. Points will not be awarded again. This attempt has been reported to the administrator.");
        return;
      }
    }

    // Add to history
    setHistory(prev => [...prev, item]);

    // Update User Stats
    if (item.isRecyclable) {
      setCurrentUser(prev => prev ? ({
        ...prev,
        totalPoints: prev.totalPoints + item.points,
        itemsRecycled: prev.itemsRecycled + 1
      }) : null);
    }
  };

  // If not authenticated, show Login screen
  if (!isAuthenticated || !currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} history={history} onLogout={handleLogout} />;
      case ViewState.MAP:
        return <InteractiveMap items={history} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative z-0">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-gray-100 pb-safe shadow-[0_-5px_15px_rgba(0,0,0,0.02)] relative z-50">
        <div className="flex justify-around items-center h-16 max-w-md mx-auto px-2">

          <button 
            onClick={() => setView(ViewState.LEADERBOARD)}
            className={`flex flex-col items-center justify-center w-14 h-full space-y-1 transition-colors ${view === ViewState.LEADERBOARD ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
