        },
        () => {},
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>, isProof: boolean = false) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    refreshLocation();

    // Create preview
    const objectUrl = URL.createObjectURL(file);

    if (isProof) {
      // Handle Proof Photo (Step 2)
      setProofImageUrl(objectUrl);
      setStep('FINAL_CONFIRM');
    } else {
      // Handle Item Photo (Step 1)
      setItemImageUrl(objectUrl);
      setStep('ANALYZING');
      setResult(null);
      setImageSignature(null);

      try {
        // Convert to base64
        const base64Promise = new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.readAsDataURL(file);
          reader.onload = () => {
              const result = reader.result as string;
              // Remove data:image/...;base64, prefix
              const base64 = result.split(',')[1];
              resolve(base64);
          };
          reader.onerror = error => reject(error);
        });

        const base64Data = await base64Promise;

        // Generate signature
        const signature = generateSignature(base64Data);
        setImageSignature(signature);

        // Analyze
        const analysis = await analyzeImage(base64Data);
        setResult(analysis);
        setStep('REVIEW_RESULT');

      } catch (err) {
        console.error(err);
        setError("Failed to analyze image. Please try again.");
        setStep('SCAN_ITEM');
      }
    }
  };

  const handleContinueToProof = () => {
    // If not recyclable, skip proof and go straight to finish (or just finish immediately)
    if (result && !result.isRecyclable) {
       handleFinalSubmit(); // No proof needed for non-recyclables
    } else {
       setStep('SCAN_PROOF');
    }
  };

  const handleFinalSubmit = () => {
    if (result && itemImageUrl) {
      const newItem: RecycleItem = {
        id: Date.now().toString(),
        name: result.itemName,
        category: result.materialCategory,
        isRecyclable: result.isRecyclable,
        points: result.estimatedPoints,
        timestamp: Date.now(),
        imageUrl: itemImageUrl,
        proofImageUrl: proofImageUrl || undefined,
        explanation: result.reasoning,
        location: location,
        imageSignature: imageSignature || undefined
      };
      onScanComplete(newItem);
      handleReset();
    }
  };

  const handleReset = () => {
    setResult(null);
    setItemImageUrl(null);
    setProofImageUrl(null);
    setError(null);
    setImageSignature(null);
    setStep('SCAN_ITEM');
    if (fileInputRef.current) fileInputRef.current.value = '';
    if (proofInputRef.current) proofInputRef.current.value = '';
  };

  // --- RENDER HELPERS ---

  const renderScanItemStep = () => (
    <div className="w-full flex flex-col items-center space-y-6">
      <div className="relative group cursor-pointer">
        <div className="absolute -inset-1 bg-gradient-to-r from-emerald-400 to-cyan-400 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-200"></div>
        <label 
          htmlFor="camera-input" 
          className="relative flex items-center justify-center w-48 h-48 bg-white rounded-full shadow-xl border-4 border-emerald-50 cursor-pointer active:scale-95 transition-transform duration-200"
        >
          <div className="flex flex-col items-center space-y-2">
            <Camera className="w-12 h-12 text-emerald-500" />
            <span className="text-sm font-semibold text-gray-500">Snap Item</span>
          </div>
        </label>
        <input 
          ref={fileInputRef}
          id="camera-input" 
          type="file" 
          accept="image/*" 
          capture="environment" 
          className="hidden" 
          onChange={(e) => handleFileChange(e, false)}
        />
      </div>
      <p className="text-xs text-gray-400 max-w-xs text-center">
        Step 1 of 2: Take a clear photo of the object you want to recycle.
      </p>
    </div>
  );

  const renderAnalyzingStep = () => (
    <div className="flex flex-col items-center space-y-4 animate-in fade-in duration-300">
      <div className="relative w-64 h-64 rounded-2xl overflow-hidden shadow-lg border-4 border-white">
        <img src={itemImageUrl || ''} alt="Analyzing" className="w-full h-full object-cover blur-sm" />
        <div className="absolute inset-0 flex items-center justify-center bg-black/30">
          <Loader2 className="w-12 h-12 text-white animate-spin" />
        </div>
      </div>
      <p className="text-emerald-700 font-medium animate-pulse">Analyzing material...</p>
    </div>
  );

  const renderReviewResultStep = () => {
    if (!result) return null;
    return (
      <div className="w-full animate-in slide-in-from-bottom-8 duration-500">
        <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-emerald-100">
          <div className="relative h-48">
            <img src={itemImageUrl || ''} alt="Scanned" className="w-full h-full object-cover" />
            <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent flex flex-col justify-end p-4">
               <h3 className="text-white text-2xl font-bold capitalize">{result.itemName}</h3>
               <div className="flex items-center space-x-2 text-emerald-100">
                 <span className="font-medium text-sm">{result.materialCategory}</span>
               </div>
            </div>
          </div>

          <div className="p-6 space-y-4">
            <div className="flex items-center justify-between">
              <div className={`flex items-center space-x-2 px-4 py-2 rounded-full ${result.isRecyclable ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                {result.isRecyclable ? <CheckCircle size={20} /> : <XCircle size={20} />}
                <span className="font-bold">{result.isRecyclable ? 'Recyclable' : 'Not Recyclable'}</span>
              </div>
            </div>

            <div className="bg-gray-50 p-4 rounded-xl text-sm text-gray-600 leading-relaxed">
              <p>{result.reasoning}</p>
            </div>

            {/* Actions */}
            <div className="flex space-x-3 pt-2">
              <button 
                onClick={handleReset}
                className="flex-1 py-3 rounded-xl border border-gray-200 text-gray-600 font-semibold hover:bg-gray-50 transition"
              >
                Retake
              </button>

              {result.isRecyclable ? (
                 <button 
                  onClick={handleContinueToProof}
                  className="flex-1 py-3 rounded-xl bg-emerald-500 text-white font-semibold shadow-lg shadow-emerald-200 hover:bg-emerald-600 transition flex items-center justify-center space-x-2"
                >
                  <span>Next: Proof</span>
                  <ArrowRight size={18} />
                </button>
              ) : (
                <button 
                  onClick={handleFinalSubmit}
                  className="flex-1 py-3 rounded-xl bg-gray-800 text-white font-semibold shadow-lg hover:bg-gray-900 transition flex items-center justify-center space-x-2"
                >
                  <span>Finish</span>
                  <ArrowRight size={18} />
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderScanProofStep = () => (
    <div className="w-full flex flex-col items-center space-y-6 animate-in slide-in-from-right duration-300">
       <div className="text-center mb-4">
         <div className="inline-block p-3 bg-emerald-100 rounded-full mb-3">
            <Trash2 className="w-8 h-8 text-emerald-600" />
         </div>
         <h3 className="text-xl font-bold text-gray-800">Prove it!</h3>
         <p className="text-gray-500 text-sm px-8">Take a photo of yourself throwing the <b>{result?.itemName}</b> into the correct bin.</p>
       </div>

      <div className="relative group cursor-pointer">
        <label 
          htmlFor="proof-input" 
          className="relative flex items-center justify-center w-48 h-48 bg-white rounded-2xl shadow-xl border-4 border-dashed border-emerald-300 cursor-pointer active:scale-95 transition-transform duration-200"
        >
          <div className="flex flex-col items-center space-y-2">
            <CameraIcon className="w-12 h-12 text-emerald-400" />
            <span className="text-sm font-semibold text-gray-500">Snap Binning</span>
          </div>
        </label>
        <input 
          ref={proofInputRef}
          id="proof-input" 
          type="file" 
          accept="image/*" 
          capture="environment" 
          className="hidden" 
          onChange={(e) => handleFileChange(e, true)}
        />
      </div>

      <button onClick={() => setStep('REVIEW_RESULT')} className="text-sm text-gray-400 underline">
        Back
      </button>
    </div>
  );

  const renderFinalConfirmStep = () => (
    <div className="w-full animate-in zoom-in-95 duration-300">
      <div className="bg-white rounded-3xl shadow-xl p-6 border border-emerald-100">
        <h3 className="text-center text-2xl font-bold text-emerald-800 mb-6">Ready to Collect?</h3>

        <div className="flex space-x-4 mb-6">
          <div className="flex-1 flex flex-col items-center space-y-2">
            <span className="text-xs font-bold text-gray-400 uppercase">The Item</span>
            <img src={itemImageUrl || ''} className="w-full h-32 object-cover rounded-xl border border-gray-200" alt="Item" />
          </div>
          <div className="flex-1 flex flex-col items-center space-y-2">
            <span className="text-xs font-bold text-gray-400 uppercase">The Proof</span>
            <img src={proofImageUrl || ''} className="w-full h-32 object-cover rounded-xl border border-gray-200" alt="Proof" />
          </div>
        </div>

        <div className="bg-emerald-50 rounded-xl p-4 mb-6 flex items-center justify-between">
            <span className="text-emerald-800 font-medium">Points to Award</span>
            <span className="text-3xl font-black text-emerald-600">+{result?.estimatedPoints}</span>
        </div>

        <button 
          onClick={handleFinalSubmit}
          className="w-full py-4 rounded-xl bg-emerald-500 text-white font-bold text-lg shadow-lg shadow-emerald-200 hover:bg-emerald-600 transition flex items-center justify-center space-x-2"
        >
          <CheckCircle className="w-6 h-6" />
          <span>Confirm & Collect</span>
        </button>

        <button onClick={() => setStep('SCAN_PROOF')} className="w-full mt-4 text-sm text-gray-400 font-medium">
          Retake Proof
        </button>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4">
      {/* Header varies by step */}
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-emerald-800">
          {step === 'SCAN_ITEM' && 'Scan Item'}
          {step === 'ANALYZING' && 'Identifying...'}
          {step === 'REVIEW_RESULT' && 'Result'}
          {step === 'SCAN_PROOF' && 'Verification'}
          {step === 'FINAL_CONFIRM' && 'Summary'}
        </h2>
        {step === 'SCAN_ITEM' && <p className="text-emerald-600">Identify rubbish & earn points</p>}
      </div>

      <div className="flex-1 flex flex-col items-center justify-center space-y-6">

        {step === 'SCAN_ITEM' && renderScanItemStep()}
        {step === 'ANALYZING' && renderAnalyzingStep()}
        {step === 'REVIEW_RESULT' && renderReviewResultStep()}
        {step === 'SCAN_PROOF' && renderScanProofStep()}
        {step === 'FINAL_CONFIRM' && renderFinalConfirmStep()}

        {/* Error State */}
        {error && (
            <div className="p-4 bg-red-50 text-red-600 rounded-xl text-center w-full">
                <p>{error}</p>
                <button onClick={handleReset} className="mt-2 text-sm underline font-semibold">Try Again</button>
            </div>
        )}

      </div>
    </div>
  );
};

