interface AchievementsProps {
  history: RecycleItem[];
  badges: string[];
}

export const ACHIEVEMENT_RULES = [
  {
    id: 'daily_10',
    title: 'Daily Warrior',
    description: 'Recycle 10 items in a single day',
    icon: <Zap className="w-6 h-6 text-yellow-500" />,
    target: 10,
    check: (history: RecycleItem[]) => {
      const dailyCounts: Record<string, number> = {};
      let maxDaily = 0;
      history.filter(i => i.isRecyclable).forEach(item => {
        const date = new Date(item.timestamp).toDateString();
        dailyCounts[date] = (dailyCounts[date] || 0) + 1;
        maxDaily = Math.max(maxDaily, dailyCounts[date]);
      });
      return { current: maxDaily, completed: maxDaily >= 10 };
    }
  },
  {
    id: 'total_10',
    title: 'Eco Starter',
    description: 'Recycle 10 items total',
    icon: <Star className="w-6 h-6 text-emerald-500" />,
    target: 10,
    check: (history: RecycleItem[]) => {
      const count = history.filter(i => i.isRecyclable).length;
      return { current: count, completed: count >= 10 };
    }
  },
  {
    id: 'total_50',
    title: 'Green Guardian',
    description: 'Recycle 50 items total',
    icon: <Medal className="w-6 h-6 text-blue-500" />,
    target: 50,
    check: (history: RecycleItem[]) => {
      const count = history.filter(i => i.isRecyclable).length;
      return { current: count, completed: count >= 50 };
    }
  },
  {
    id: 'total_100',
    title: 'Planet Hero',
    description: 'Recycle 100 items total',
    icon: <Trophy className="w-6 h-6 text-purple-500" />,
    target: 100,
    check: (history: RecycleItem[]) => {
      const count = history.filter(i => i.isRecyclable).length;
      return { current: count, completed: count >= 100 };
    }
  }
];

export const Achievements: React.FC<AchievementsProps> = ({ history, badges }) => {
  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4 overflow-y-auto no-scrollbar pb-24">
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-emerald-800">Achievements</h2>
        <p className="text-emerald-600">Unlock badges as you save the planet</p>
