          const progress = Math.min(100, (status.current / achievement.target) * 100);

          return (
            <div 
              key={achievement.id} 
              className={`relative rounded-2xl p-4 border transition-all duration-300 ${
                isUnlocked 
                  ? 'bg-white border-emerald-200 shadow-md' 
                  : 'bg-gray-50 border-gray-200 grayscale opacity-90'
              }`}
            >
              <div className="flex items-center space-x-4">
                <div className={`w-14 h-14 rounded-full flex items-center justify-center ${isUnlocked ? 'bg-emerald-50' : 'bg-gray-200'}`}>
                  {isUnlocked ? achievement.icon : <Lock className="w-6 h-6 text-gray-400" />}
                </div>

                <div className="flex-1">
                  <h3 className={`font-bold ${isUnlocked ? 'text-gray-800' : 'text-gray-500'}`}>
                    {achievement.title}
                  </h3>
                  <p className="text-sm text-gray-500 mb-2">{achievement.description}</p>

                  {/* Progress Bar */}
                  <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
                    <div 
                      className={`h-2 rounded-full transition-all duration-500 ${isUnlocked ? 'bg-gradient-to-r from-emerald-400 to-teal-500' : 'bg-gray-400'}`}
                      style={{ width: `${progress}%` }}
                    />
                  </div>
                  <div className="flex justify-between mt-1">
                    <span className="text-[10px] text-gray-400 font-medium">
                      {status.current} / {achievement.target}
                    </span>
                    {isUnlocked && (
                       <span className="text-[10px] font-bold text-emerald-600 bg-emerald-100 px-2 py-0.5 rounded-full">
                         UNLOCKED
                       </span>
                    )}
