                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { Achievements, ACHIEVEMENT_RULES } from './components/Achievements';
import { User, RecycleItem, ViewState } from './types';
import { Scan, BarChart2, User as UserIcon, Map as MapIcon, Award } from 'lucide-react';

// Start with an empty user list
const INITIAL_USERS: User[] = [];

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [history, setHistory] = useState<RecycleItem[]>([]);

  // Update users list when current user changes (e.g. after login or point update)
  useEffect(() => {
    if (currentUser) {
      setUsers(prevUsers => {
        // Remove previous instance of current user if exists
        const otherUsers = prevUsers.filter(u => u.id !== currentUser.id);
        return [...otherUsers, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setHistory([]);
    setUsers([]); // Clear users on logout so next login starts fresh
    setView(ViewState.SCANNER);
  };

  const checkAchievements = (updatedHistory: RecycleItem[], user: User): string[] => {
    const newBadges: string[] = [];

    ACHIEVEMENT_RULES.forEach(rule => {
      // If user doesn't have this badge yet
      if (!user.badges.includes(rule.id)) {
        const { completed } = rule.check(updatedHistory);
        if (completed) {
          newBadges.push(rule.id);
        }
      }
    });

    return newBadges;
  };

  const handleScanComplete = (item: RecycleItem) => {
    if (!currentUser) return;

    // Security Check: Prevent duplicate uploads
    if (item.imageSignature) {
      const isDuplicate = history.some(historyItem => historyItem.imageSignature === item.imageSignature);
      if (isDuplicate) {
        // Alert the administrator (simulated via console)
        console.warn(`[ADMIN ALERT] User ${currentUser.name} (ID: ${currentUser.id}) attempted to upload a duplicate image. Signature: ${item.imageSignature}`);

        // Alert the user
        alert("⚠️ Duplicate Image Detected!\n\nThis image has already been submitted. Points will not be awarded again. This attempt has been reported.");
        return;
      }
    }

    // Add to history
    const updatedHistory = [...history, item];
    setHistory(updatedHistory);

    // Update User Stats and Check Achievements
    if (item.isRecyclable) {
      const newBadges = checkAchievements(updatedHistory, currentUser);

      if (newBadges.length > 0) {
        alert(`🎉 Congratulations! You've unlocked ${newBadges.length} new achievement(s)!`);
      }

      setCurrentUser(prev => prev ? ({
        ...prev,
        totalPoints: prev.totalPoints + item.points,
        itemsRecycled: prev.itemsRecycled + 1,
        badges: [...prev.badges, ...newBadges]
      }) : null);
    }
  };

  // If not authenticated, show Login screen
  if (!isAuthenticated || !currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} history={history} onLogout={handleLogout} />;
      case ViewState.MAP:
        return <InteractiveMap items={history} />;
      case ViewState.ACHIEVEMENTS:
        return <Achievements history={history} badges={currentUser.badges} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative z-0">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-gray-100 pb-safe shadow-[0_-5px_15px_rgba(0,0,0,0.02)] relative z-50">
        <div className="flex justify-between items-center h-16 max-w-md mx-auto px-2">

          <button 
            onClick={() => setView(ViewState.LEADERBOARD)}
            className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.LEADERBOARD ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <BarChart2 className={`w-5 h-5 ${view === ViewState.LEADERBOARD ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Rank</span>
          </button>

          <button 
            onClick={() => setView(ViewState.ACHIEVEMENTS)}
            className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.ACHIEVEMENTS ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <Award className={`w-5 h-5 ${view === ViewState.ACHIEVEMENTS ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Awards</span>
          </button>

          <button 
            onClick={() => setView(ViewState.SCANNER)}
            className="flex flex-col items-center justify-center -mt-6 relative z-50"
          >
             <div className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-transform duration-200 ${view === ViewState.SCANNER ? 'bg-emerald-500 scale-110 shadow-emerald-200' : 'bg-gray-800 hover:scale-105'}`}>
               <Scan className="w-7 h-7 text-white" />
             </div>
             <span className={`text-[10px] font-medium mt-1 ${view === ViewState.SCANNER ? 'text-emerald-600' : 'text-gray-400'}`}>Scan</span>
          </button>

          <button 
            onClick={() => setView(ViewState.MAP)}
            className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.MAP ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <MapIcon className={`w-5 h-5 ${view === ViewState.MAP ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Map</span>
          </button>

          <button 
             onClick={() => setView(ViewState.PROFILE)}
             className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.PROFILE ? 'text-emerald-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <UserIcon className={`w-5 h-5 ${view === ViewState.PROFILE ? 'fill-emerald-100' : ''}`} />
            <span className="text-[10px] font-medium">Profile</span>
          </button>

        </div>
      </nav>
    </div>
  );
}

import React, { useEffect, useRef } from 'react';
import * as L from 'leaflet';
import { RecycleItem } from '../types';
import { MapPin } from 'lucide-react';

interface InteractiveMapProps {
  items: RecycleItem[];
}

export const InteractiveMap: React.FC<InteractiveMapProps> = ({ items }) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

