import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { Achievements, ACHIEVEMENT_RULES } from './components/Achievements';
import { WaypointInfo } from './components/WaypointInfo';
import { User, RecycleItem, ViewState } from './types';
import { Scan, BarChart2, User as UserIcon, Map as MapIcon, Award } from 'lucide-react';

// Start with an empty user list
const INITIAL_USERS: User[] = [];

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [history, setHistory] = useState<RecycleItem[]>([]);

  // Update users list when current user changes (e.g. after login or point update)
  useEffect(() => {
    if (currentUser) {
      setUsers(prevUsers => {
        // Remove previous instance of current user if exists
        const otherUsers = prevUsers.filter(u => u.id !== currentUser.id);
        return [...otherUsers, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setHistory([]);
    setUsers([]); // Clear users on logout so next login starts fresh
    setView(ViewState.SCANNER);
  };

  const checkAchievements = (updatedHistory: RecycleItem[], user: User): string[] => {
    const newBadges: string[] = [];

    ACHIEVEMENT_RULES.forEach(rule => {
      // If user doesn't have this badge yet
      if (!user.badges.includes(rule.id)) {
        const { completed } = rule.check(updatedHistory);
        if (completed) {
          newBadges.push(rule.id);
        }
      }
    });

    return newBadges;
  };

  const handleScanComplete = (item: RecycleItem) => {
    if (!currentUser) return;

    // Security Check: Prevent duplicate uploads
    if (item.imageSignature) {
      const isDuplicate = history.some(historyItem => historyItem.imageSignature === item.imageSignature);
      if (isDuplicate) {
        // Alert the administrator (simulated via console)
        console.warn(`[ADMIN ALERT] User ${currentUser.name} (ID: ${currentUser.id}) attempted to upload a duplicate image. Signature: ${item.imageSignature}`);

        // Alert the user
        alert("⚠️ Duplicate Image Detected!\n\nThis image has already been submitted. Points will not be awarded again. This attempt has been reported.");
        return;
      }
    }

    // Add to history
    const updatedHistory = [...history, item];
    setHistory(updatedHistory);

    // Update User Stats and Check Achievements
    if (item.isRecyclable) {
      const newBadges = checkAchievements(updatedHistory, currentUser);

      if (newBadges.length > 0) {
        alert(`🎉 Congratulations! You've unlocked ${newBadges.length} new achievement(s)!`);
      }

      setCurrentUser(prev => prev ? ({
        ...prev,
        totalPoints: prev.totalPoints + item.points,
        itemsRecycled: prev.itemsRecycled + 1,
        badges: [...prev.badges, ...newBadges]
      }) : null);
    }
  };

  // If not authenticated, show Login screen
  if (!isAuthenticated || !currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} history={history} onLogout={handleLogout} />;
      case ViewState.MAP:
        return (
          <InteractiveMap 
            items={history} 
            onViewWaypointInfo={() => setView(ViewState.WAYPOINT_INFO)} 
          />
        );
      case ViewState.ACHIEVEMENTS:
        return <Achievements history={history} badges={currentUser.badges} />;
      case ViewState.WAYPOINT_INFO:
        return <WaypointInfo onBack={() => setView(ViewState.MAP)} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative z-0">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      {view !== ViewState.WAYPOINT_INFO && (
