import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeImage = async (base64Image: string): Promise<AnalysisResult> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          {
            text: `Analyze this image to identify the animal or wildlife present.
            Provide a strict JSON response.
            Determine the common name, scientific name, and class (Mammal, Bird, Reptile, Amphibian, Insect, Arachnid, Marine, Other).

            Scoring Rules:
            - If it is a clear image of a living animal/insect: 10 points.
            - If it is a Domestic Pet (Cat/Dog): 5 points.
            - If it is NOT an animal (e.g., plant, object, human): 0 points and mark isWildlife as false.

            Provide the IUCN conservation status if known (e.g., "Least Concern", "Vulnerable", "Endangered", "Domesticated").
            Provide a short description and a fun fact.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            speciesName: { type: Type.STRING },
            scientificName: { type: Type.STRING },
            category: { type: Type.STRING, enum: ["Mammal", "Bird", "Reptile", "Amphibian", "Insect", "Arachnid", "Marine", "Other"] },
            isWildlife: { type: Type.BOOLEAN },
            description: { type: Type.STRING },
            conservationStatus: { type: Type.STRING },
            estimatedPoints: { type: Type.INTEGER },
            funFact: { type: Type.STRING }
          },
          required: ["speciesName", "scientificName", "category", "isWildlife", "description", "conservationStatus", "estimatedPoints", "funFact"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text from Gemini");

    const result = JSON.parse(text) as AnalysisResult;
    return result;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, CheckCircle, XCircle, Loader2, ArrowRight, MapPin, ScanLine, Bird } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult, WildlifeEntry } from '../types';

interface ScannerProps {
  onScanComplete: (item: WildlifeEntry) => void;
}

// Simple string hash function to generate a signature for the image data
const generateSignature = (str: string): string => {
  let hash = 0;
  if (str.length === 0) return hash.toString();
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  return hash.toString();
};

type ScanStep = 'SCAN_ANIMAL' | 'ANALYZING' | 'REVIEW_RESULT';

export const Scanner: React.FC<ScannerProps> = ({ onScanComplete }) => {
  const [step, setStep] = useState<ScanStep>('SCAN_ANIMAL');

  // Data
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [itemImageUrl, setItemImageUrl] = useState<string | null>(null);
  const [imageSignature, setImageSignature] = useState<string | null>(null);
  const [location, setLocation] = useState<{lat: number, lng: number} | undefined>(undefined);

  // UI State
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Attempt to get location quietly when component mounts
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
        },
        (err) => console.log("Location pre-fetch failed/denied", err),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  }, []);

  const refreshLocation = () => {
    if (navigator.geolocation) {
       navigator.geolocation.getCurrentPosition(
        (position) => {
          setLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
        },
        () => {},
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setError(null);
    refreshLocation();

    // Create preview
    const objectUrl = URL.createObjectURL(file);
    setItemImageUrl(objectUrl);
    setStep('ANALYZING');
    setResult(null);
    setImageSignature(null);

    try {
      // Convert to base64
      const base64Promise = new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            // Remove data:image/...;base64, prefix
            const base64 = result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = error => reject(error);
      });

      const base64Data = await base64Promise;

      // Generate signature
      const signature = generateSignature(base64Data);
      setImageSignature(signature);

      // Analyze
      const analysis = await analyzeImage(base64Data);
      setResult(analysis);
      setStep('REVIEW_RESULT');

    } catch (err) {
      console.error(err);
      setError("Failed to identify species. Please ensure the subject is clear.");
      setStep('SCAN_ANIMAL');
    }
  };

  const handleFinalSubmit = () => {
    if (result && itemImageUrl) {
      const newEntry: WildlifeEntry = {
        id: Date.now().toString(),
        speciesName: result.speciesName,
        scientificName: result.scientificName,
        category: result.category,
        isWildlife: result.isWildlife,
        points: result.estimatedPoints,
        timestamp: Date.now(),
        imageUrl: itemImageUrl,
        description: result.description,
        conservationStatus: result.conservationStatus,
        location: location,
        imageSignature: imageSignature || undefined
      };
      onScanComplete(newEntry);
      handleReset();
    }
  };

  const handleReset = () => {
    setResult(null);
    setItemImageUrl(null);
    setError(null);
    setImageSignature(null);
    setStep('SCAN_ANIMAL');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  // --- RENDER HELPERS ---

  const renderScanStep = () => (
    <div className="w-full flex flex-col items-center space-y-6">
      <div className="relative group cursor-pointer">
        <div className="absolute -inset-1 bg-gradient-to-r from-amber-400 to-orange-500 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-200"></div>
        <label 
          htmlFor="camera-input" 
          className="relative flex items-center justify-center w-48 h-48 bg-stone-100 rounded-full shadow-xl border-4 border-amber-50 cursor-pointer active:scale-95 transition-transform duration-200"
        >
          <div className="flex flex-col items-center space-y-2">
            <Camera className="w-12 h-12 text-amber-600" />
            <span className="text-sm font-semibold text-stone-600">Spot Animal</span>
          </div>
        </label>
        <input 
          ref={fileInputRef}
          id="camera-input" 
          type="file" 
          accept="image/*" 
          capture="environment" 
          className="hidden" 
          onChange={handleFileChange}
        />
      </div>
      <p className="text-xs text-stone-500 max-w-xs text-center">
        Step 1: Take a clear photo of an animal, insect, or bird.
      </p>
    </div>
  );

  const renderAnalyzingStep = () => (
    <div className="flex flex-col items-center space-y-4 animate-in fade-in duration-300">
      <div className="relative w-64 h-64 rounded-2xl overflow-hidden shadow-lg border-4 border-white">
        <img src={itemImageUrl || ''} alt="Analyzing" className="w-full h-full object-cover blur-sm" />
        <div className="absolute inset-0 flex items-center justify-center bg-black/30">
          <Loader2 className="w-12 h-12 text-white animate-spin" />
        </div>
      </div>
      <p className="text-amber-800 font-medium animate-pulse">Consulting Field Guide...</p>
    </div>
  );

  const renderReviewResultStep = () => {
    if (!result) return null;
    return (
      <div className="w-full animate-in slide-in-from-bottom-8 duration-500">
        <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-amber-100">
          <div className="relative h-56">
            <img src={itemImageUrl || ''} alt="Scanned" className="w-full h-full object-cover" />
            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent flex flex-col justify-end p-5">
               <h3 className="text-white text-2xl font-bold capitalize shadow-sm">{result.speciesName}</h3>
               <p className="text-amber-200 text-sm italic font-serif">{result.scientificName}</p>
            </div>
          </div>

          <div className="p-6 space-y-4">
            <div className="flex items-center justify-between">
              <div className={`flex items-center space-x-2 px-4 py-2 rounded-full ${result.isWildlife ? 'bg-amber-100 text-amber-800' : 'bg-red-100 text-red-700'}`}>
                {result.isWildlife ? <Bird size={20} /> : <XCircle size={20} />}
                <span className="font-bold">{result.category}</span>
              </div>
              {result.isWildlife && (
                <div className="px-3 py-1 bg-stone-100 text-stone-600 rounded-lg text-xs font-bold uppercase tracking-wider">
                  {result.conservationStatus}
                </div>
              )}
            </div>

            <div className="bg-stone-50 p-4 rounded-xl text-sm text-stone-700 leading-relaxed border-l-4 border-amber-400">
              <p>{result.description}</p>
              {result.funFact && (
                <p className="mt-3 text-xs text-stone-500 italic">Did you know? {result.funFact}</p>
              )}
            </div>

            {/* Actions */}
            <div className="flex space-x-3 pt-2">
              <button 
                onClick={handleReset}
                className="flex-1 py-3 rounded-xl border border-stone-200 text-stone-600 font-semibold hover:bg-stone-50 transition"
              >
                Discard
              </button>

              {result.isWildlife ? (
                 <button 
                  onClick={handleFinalSubmit}
                  className="flex-1 py-3 rounded-xl bg-amber-600 text-white font-semibold shadow-lg shadow-amber-200 hover:bg-amber-700 transition flex items-center justify-center space-x-2"
                >
                  <CheckCircle size={18} />
                  <span>Log Sighting (+{result.estimatedPoints})</span>
                </button>
              ) : (
                <div className="flex-1 py-3 rounded-xl bg-gray-100 text-gray-400 font-semibold flex items-center justify-center text-sm">
                  Not Wildlife
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4">
      {/* Header varies by step */}
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-stone-800">
          {step === 'SCAN_ANIMAL' && 'Identify Wildlife'}
          {step === 'ANALYZING' && 'Processing...'}
          {step === 'REVIEW_RESULT' && 'New Discovery'}
        </h2>
        {step === 'SCAN_ANIMAL' && <p className="text-stone-500">Document biodiversity around you</p>}
      </div>

      <div className="flex-1 flex flex-col items-center justify-center space-y-6">

        {step === 'SCAN_ANIMAL' && renderScanStep()}
        {step === 'ANALYZING' && renderAnalyzingStep()}
        {step === 'REVIEW_RESULT' && renderReviewResultStep()}

        {/* Error State */}
        {error && (
            <div className="p-4 bg-red-50 text-red-600 rounded-xl text-center w-full border border-red-100">
                <p>{error}</p>
                <button onClick={handleReset} className="mt-2 text-sm underline font-semibold">Try Again</button>
            </div>
        )}

      </div>
    </div>
  );
};

