      return { current: birds.length, completed: birds.length >= 3 };
    }
  },
  {
    id: 'entomologist',
    title: 'Bug Catcher',
    description: 'Spot 5 insects or arachnids',
    icon: <Bug className="w-6 h-6 text-green-600" />,
    target: 5,
    check: (history: WildlifeEntry[]) => {
      const bugs = history.filter(i => i.isWildlife && (i.category === 'Insect' || i.category === 'Arachnid'));
      return { current: bugs.length, completed: bugs.length >= 5 };
    }
  },
  {
    id: 'ranger_elite',
    title: 'Ranger Elite',
    description: 'Log 20 total sightings',
    icon: <Binoculars className="w-6 h-6 text-orange-600" />,
