export const Achievements: React.FC<AchievementsProps> = ({ history, badges }) => {
  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4 overflow-y-auto no-scrollbar pb-24">
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-stone-800">Ranger Badges</h2>
        <p className="text-stone-600">Unlock skills as you explore nature</p>
      </div>

      <div className="space-y-4">
        {ACHIEVEMENT_RULES.map((achievement) => {
          const status = achievement.check(history);
          const isUnlocked = badges.includes(achievement.id) || status.completed;
          const progress = Math.min(100, (status.current / achievement.target) * 100);

          return (
            <div 
              key={achievement.id} 
              className={`relative rounded-2xl p-4 border transition-all duration-300 ${
                isUnlocked 
                  ? 'bg-white border-amber-200 shadow-md' 
                  : 'bg-stone-50 border-stone-200 grayscale opacity-90'
              }`}
            >
              <div className="flex items-center space-x-4">
                <div className={`w-14 h-14 rounded-full flex items-center justify-center ${isUnlocked ? 'bg-amber-50' : 'bg-stone-200'}`}>
                  {isUnlocked ? achievement.icon : <Lock className="w-6 h-6 text-stone-400" />}
                </div>

                <div className="flex-1">
                  <h3 className={`font-bold ${isUnlocked ? 'text-stone-800' : 'text-stone-500'}`}>
                    {achievement.title}
                  </h3>
                  <p className="text-sm text-stone-500 mb-2">{achievement.description}</p>

                  {/* Progress Bar */}
                  <div className="w-full bg-stone-200 rounded-full h-2 overflow-hidden">
                    <div 
                      className={`h-2 rounded-full transition-all duration-500 ${isUnlocked ? 'bg-gradient-to-r from-amber-400 to-orange-500' : 'bg-stone-400'}`}
                      style={{ width: `${progress}%` }}
                    />
                  </div>
                  <div className="flex justify-between mt-1">
                    <span className="text-[10px] text-stone-400 font-medium">
                      {status.current} / {achievement.target}
                    </span>
                    {isUnlocked && (
                       <span className="text-[10px] font-bold text-amber-600 bg-amber-100 px-2 py-0.5 rounded-full">
                         EARNED
                       </span>
                    )}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { Achievements, ACHIEVEMENT_RULES } from './components/Achievements';
import { WaypointInfo } from './components/WaypointInfo';
import { User, WildlifeEntry, ViewState } from './types';
import { Scan, Compass, User as UserIcon, Map as MapIcon, Award } from 'lucide-react';

// Start with an empty user list
const INITIAL_USERS: User[] = [];

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [logbook, setLogbook] = useState<WildlifeEntry[]>([]);

  // Update users list when current user changes (e.g. after login or point update)
  useEffect(() => {
    if (currentUser) {
      setUsers(prevUsers => {
        // Remove previous instance of current user if exists
        const otherUsers = prevUsers.filter(u => u.id !== currentUser.id);
        return [...otherUsers, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setLogbook([]);
    setUsers([]); // Clear users on logout so next login starts fresh
    setView(ViewState.SCANNER);
  };

  const checkAchievements = (updatedLogbook: WildlifeEntry[], user: User): string[] => {
    const newBadges: string[] = [];

    ACHIEVEMENT_RULES.forEach(rule => {
      // If user doesn't have this badge yet
      if (!user.badges.includes(rule.id)) {
        const { completed } = rule.check(updatedLogbook);
        if (completed) {
          newBadges.push(rule.id);
        }
      }
    });

    return newBadges;
  };

  const handleScanComplete = (entry: WildlifeEntry) => {
    if (!currentUser) return;

    // Security Check: Prevent duplicate uploads
    if (entry.imageSignature) {
      const isDuplicate = logbook.some(existingEntry => existingEntry.imageSignature === entry.imageSignature);
      if (isDuplicate) {
        // Alert the administrator (simulated via console)
        console.warn(`[ADMIN ALERT] User ${currentUser.name} (ID: ${currentUser.id}) attempted to upload a duplicate image. Signature: ${entry.imageSignature}`);

        // Alert the user
        alert("⚠️ Duplicate Sighting Detected!\n\nThis photo has already been logged. Points will not be awarded again.");
        return;
      }
    }

    // Add to logbook
    const updatedLogbook = [...logbook, entry];
    setLogbook(updatedLogbook);

    // Update User Stats and Check Achievements
    if (entry.isWildlife) {
      const newBadges = checkAchievements(updatedLogbook, currentUser);

      if (newBadges.length > 0) {
        alert(`🎉 Congratulations Ranger! You've unlocked ${newBadges.length} new badge(s)!`);
      }

      setCurrentUser(prev => prev ? ({
        ...prev,
        totalPoints: prev.totalPoints + entry.points,
        sightingsLogged: prev.sightingsLogged + 1,
        badges: [...prev.badges, ...newBadges]
      }) : null);
    }
  };

  // If not authenticated, show Login screen
  if (!isAuthenticated || !currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} logbook={logbook} onLogout={handleLogout} />;
      case ViewState.MAP:
        return (
          <InteractiveMap 
            items={logbook} 
            onViewWaypointInfo={() => setView(ViewState.WAYPOINT_INFO)} 
          />
        );
      case ViewState.ACHIEVEMENTS:
        return <Achievements history={logbook} badges={currentUser.badges} />;
      case ViewState.WAYPOINT_INFO:
        return <WaypointInfo onBack={() => setView(ViewState.MAP)} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-stone-50 text-stone-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative z-0">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      {view !== ViewState.WAYPOINT_INFO && (
        <nav className="bg-white border-t border-stone-200 pb-safe shadow-[0_-5px_15px_rgba(0,0,0,0.02)] relative z-50">
          <div className="flex justify-between items-center h-16 max-w-md mx-auto px-2">

            <button 
              onClick={() => setView(ViewState.LEADERBOARD)}
              className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.LEADERBOARD ? 'text-amber-600' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <Compass className={`w-5 h-5 ${view === ViewState.LEADERBOARD ? 'fill-amber-100' : ''}`} />
              <span className="text-[10px] font-medium">Ranks</span>
            </button>

            <button 
              onClick={() => setView(ViewState.ACHIEVEMENTS)}
              className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.ACHIEVEMENTS ? 'text-amber-600' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <Award className={`w-5 h-5 ${view === ViewState.ACHIEVEMENTS ? 'fill-amber-100' : ''}`} />
              <span className="text-[10px] font-medium">Badges</span>
            </button>

            <button 
              onClick={() => setView(ViewState.SCANNER)}
              className="flex flex-col items-center justify-center -mt-6 relative z-50"
            >
               <div className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-transform duration-200 ${view === ViewState.SCANNER ? 'bg-amber-600 scale-110 shadow-amber-200' : 'bg-stone-800 hover:scale-105'}`}>
                 <Scan className="w-7 h-7 text-white" />
               </div>
               <span className={`text-[10px] font-medium mt-1 ${view === ViewState.SCANNER ? 'text-amber-600' : 'text-stone-400'}`}>Spot</span>
            </button>

            <button 
              onClick={() => setView(ViewState.MAP)}
              className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.MAP ? 'text-amber-600' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <MapIcon className={`w-5 h-5 ${view === ViewState.MAP ? 'fill-amber-100' : ''}`} />
              <span className="text-[10px] font-medium">Map</span>
            </button>

            <button 
               onClick={() => setView(ViewState.PROFILE)}
               className={`flex flex-col items-center justify-center w-12 h-full space-y-1 transition-colors ${view === ViewState.PROFILE ? 'text-amber-600' : 'text-stone-400 hover:text-stone-600'}`}
            >
              <UserIcon className={`w-5 h-5 ${view === ViewState.PROFILE ? 'fill-amber-100' : ''}`} />
              <span className="text-[10px] font-medium">Journal</span>
            </button>

          </div>
        </nav>
      )}
    </div>
  );
}

