export const AnimalsList: React.FC<AnimalsListProps> = ({ items }) => {
  // 1. Process User's Logbook
  // Create a map of species user has found. We use a normalized string for fuzzy matching.
  const userFoundMap = new Map<string, WildlifeEntry>();
  const otherDiscoveries: WildlifeEntry[] = [];

  items.forEach(item => {
    if (item.isWildlife) {
      // Simple normalization for matching
      const normName = item.speciesName.toLowerCase();

      // Check if this item matches any in the Sanctuary Checklist
      const matchedSpecies = SANCTUARY_SPECIES.find(s => 
        normName.includes(s.name.toLowerCase()) || 
        s.name.toLowerCase().includes(normName)
      );

      if (matchedSpecies) {
        // Only keep the most recent/best entry for the checklist display
        if (!userFoundMap.has(matchedSpecies.name)) {
          userFoundMap.set(matchedSpecies.name, item);
        }
      } else {
        // If it's not in the checklist, add to "Other Discoveries"
        // Avoid duplicates in Other Discoveries for display purposes
        const isDuplicate = otherDiscoveries.some(d => d.speciesName === item.speciesName);
        if (!isDuplicate) {
          otherDiscoveries.push(item);
        }
      }
    }
  });

  const renderCard = (
    title: string, 
    subtitle: string, 
    category: string, 
    userImage?: string, 
    referenceImage?: string,
    chinese?: string,
    isChecklist = false
  ) => {
    const isFound = !!userImage;
    // Use user's image if found, otherwise use reference image (if checklist)
    const displayImage = userImage || referenceImage;

    return (
      <div className={`rounded-xl overflow-hidden shadow-sm border flex flex-col transition-all ${isFound ? 'bg-white border-amber-100' : 'bg-stone-50 border-stone-200'}`}>
        <div className="h-32 w-full relative bg-stone-200 overflow-hidden">
          {displayImage ? (
            <div className="relative w-full h-full">
                <img 
                  src={displayImage} 
                  alt={title} 
                  className={`w-full h-full object-cover transition-all duration-500 ${isFound ? '' : 'grayscale contrast-50 opacity-75 blur-[1px]'}`}
                />
                {!isFound && (
                    <div className="absolute inset-0 flex items-center justify-center bg-stone-900/10">
                        <Lock className="text-white/80 drop-shadow-md" size={24} />
                    </div>
                )}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-stone-300">
               {category === 'Bird' ? <Bird size={32} /> : category === 'Mammal' ? <Cat size={32} /> : <HelpCircle size={32} />}
               <span className="text-[10px] mt-2 font-medium text-stone-400">Not Discovered</span>
            </div>
          )}

          <div className="absolute top-2 right-2 flex space-x-1 z-10">
            <span className={`px-2 py-0.5 backdrop-blur-md text-[10px] font-bold rounded-full uppercase ${isFound ? 'bg-black/50 text-white' : 'bg-stone-800/50 text-stone-200'}`}>
              {category}
            </span>
          </div>

          {isChecklist && (
             <div className="absolute bottom-2 right-2 z-10">
                {isFound ? (
                   <div className="bg-green-500 text-white p-1 rounded-full shadow-lg border-2 border-white animate-in zoom-in">
                      <CheckCircle2 size={16} />
                   </div>
                ) : (
                   <div className="bg-black/20 text-white p-1 rounded-full backdrop-blur-sm border border-white/30">
                      <Circle size={16} />
                   </div>
                )}
             </div>
          )}
        </div>

        <div className="p-3 flex-1 flex flex-col">
          <div className="flex justify-between items-start">
             <h3 className={`font-bold text-sm capitalize mb-0.5 leading-tight ${isFound ? 'text-stone-800' : 'text-stone-500'}`}>
                {title}
              </h3>
          </div>

          {chinese && <p className={`text-xs font-medium mb-1 ${isFound ? 'text-amber-600' : 'text-stone-400'}`}>{chinese}</p>}

          <p className={`text-[10px] italic font-serif mb-2 line-clamp-1 ${isFound ? 'text-stone-500' : 'text-stone-400'}`}>
            {subtitle}
          </p>

          <div className="mt-auto">
             {isFound ? (
                <span className="inline-block px-1.5 py-0.5 bg-amber-50 text-amber-700 text-[10px] rounded border border-amber-100 font-medium">
                  Collected
                </span>
             ) : (
                <span className="inline-block px-1.5 py-0.5 bg-stone-100 text-stone-400 text-[10px] rounded border border-stone-200">
                  Undiscovered
                </span>
             )}
          </div>
        </div>
      </div>
    );
  };

  const discoveredCount = userFoundMap.size;
  const totalCount = SANCTUARY_SPECIES.length;
  const progress = (discoveredCount / totalCount) * 100;

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4 overflow-y-auto no-scrollbar pb-24">

      {/* Header & Progress */}
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-stone-800">Field Guide</h2>
        <div className="flex items-center justify-between text-sm text-stone-600 mb-2">
           <span>Sanctuary Collection</span>
           <span className="font-bold text-amber-600">{discoveredCount}/{totalCount} Found</span>
        </div>
        <div className="w-full bg-stone-200 rounded-full h-2.5 overflow-hidden">
            <div 
              className="bg-gradient-to-r from-amber-500 to-orange-600 h-full rounded-full transition-all duration-700" 
              style={{ width: `${progress}%` }} 
            />
        </div>
      </div>

      {/* Sanctuary Checklist Grid */}
      <div className="mb-8">
        <h3 className="text-sm font-bold text-stone-500 uppercase tracking-wider mb-3">Sanctuary Checklist</h3>
        <div className="grid grid-cols-2 gap-4">
          {SANCTUARY_SPECIES.map((species, idx) => {
            const entry = userFoundMap.get(species.name);
            return (
              <div key={idx}>
                {renderCard(
                   species.name, 
                   species.scientific, 
                   species.category, 
                   entry?.imageUrl, // user image
                   species.image,   // reference image
                   species.chinese,
                   true
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Other Discoveries */}
      {otherDiscoveries.length > 0 && (
        <div className="mb-8">
          <h3 className="text-sm font-bold text-stone-500 uppercase tracking-wider mb-3 flex items-center">
             <span>Other Discoveries</span>
             <span className="ml-2 bg-stone-100 text-stone-600 px-2 py-0.5 rounded-full text-[10px]">{otherDiscoveries.length}</span>
          </h3>
          <div className="grid grid-cols-2 gap-4">
            {otherDiscoveries.map((animal) => (
              <div key={animal.id}>
                {renderCard(
                  animal.speciesName,
                  animal.scientificName,
                  animal.category,
                  animal.imageUrl
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {discoveredCount === 0 && otherDiscoveries.length === 0 && (
         <div className="p-6 text-center bg-amber-50 rounded-2xl border border-amber-100 mx-4">
            <p className="text-amber-800 font-medium text-sm">Start your adventure!</p>
            <p className="text-amber-600 text-xs mt-1">Look for the animals in the checklist above.</p>
         </div>
      )}

    </div>
  );
};

