import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { Achievements, ACHIEVEMENT_RULES } from './components/Achievements';
import { WaypointInfo } from './components/WaypointInfo';
import { AnimalsList } from './components/AnimalsList';
import { User, WildlifeEntry, ViewState } from './types';
import { Scan, Compass, User as UserIcon, Map as MapIcon, Award, BookOpen } from 'lucide-react';

// Start with an empty user list
const INITIAL_USERS: User[] = [];

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [logbook, setLogbook] = useState<WildlifeEntry[]>([]);
  const [manualLocation, setManualLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  const [isSelectingLocation, setIsSelectingLocation] = useState(false);

  // Update users list when current user changes (e.g. after login or point update)
  useEffect(() => {
    if (currentUser) {
      setUsers(prevUsers => {
        // Remove previous instance of current user if exists
        const otherUsers = prevUsers.filter(u => u.id !== currentUser.id);
        return [...otherUsers, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setLogbook([]);
    setUsers([]); // Clear users on logout so next login starts fresh
    setView(ViewState.SCANNER);
    setManualLocation(undefined);
    setIsSelectingLocation(false);
  };

  const checkAchievements = (updatedLogbook: WildlifeEntry[], user: User): string[] => {
    const newBadges: string[] = [];

    ACHIEVEMENT_RULES.forEach(rule => {
      // If user doesn't have this badge yet
      if (!user.badges.includes(rule.id)) {
        const { completed } = rule.check(updatedLogbook);
        if (completed) {
          newBadges.push(rule.id);
        }
      }
    });

    return newBadges;
  };

  const handleScanComplete = (entry: WildlifeEntry) => {
    if (!currentUser) return;

    // Security Check: Prevent duplicate uploads
    if (entry.imageSignature) {
      const isDuplicate = logbook.some(existingEntry => existingEntry.imageSignature === entry.imageSignature);
      if (isDuplicate) {
        // Alert the administrator (simulated via console)
        console.warn(`[ADMIN ALERT] User ${currentUser.name} (ID: ${currentUser.id}) attempted to upload a duplicate image. Signature: ${entry.imageSignature}`);

        // Alert the user
        alert("⚠️ Duplicate Sighting Detected!\n\nThis photo has already been logged. Points will not be awarded again.");
        return;
      }
    }

    // Augment entry with User details
    const entryWithUser: WildlifeEntry = {
      ...entry,
      userId: currentUser.id,
      userName: currentUser.name,
      userAvatar: currentUser.avatar,
    };

    // Add to logbook
    const updatedLogbook = [...logbook, entryWithUser];
    setLogbook(updatedLogbook);
    setManualLocation(undefined); // Reset manual location after use

    // Update User Stats and Check Achievements
    if (entry.isWildlife) {
      const newBadges = checkAchievements(updatedLogbook, currentUser);

      if (newBadges.length > 0) {
        alert(`🎉 Congratulations Ranger! You've unlocked ${newBadges.length} new badge(s)!`);
      }

      setCurrentUser(prev => prev ? ({
        ...prev,
        totalPoints: prev.totalPoints + entry.points,
        sightingsLogged: prev.sightingsLogged + 1,
        badges: Array.from(new Set([...prev.badges, ...newBadges]))
      }) : null);
    }
  };

  // If not authenticated, show Login screen
  if (!isAuthenticated || !currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  // Filter logbook for map to only show active sightings (last 24h)
  const mapItems = logbook.filter(entry => {
    const oneDayMs = 24 * 60 * 60 * 1000;
    return (Date.now() - entry.timestamp) < oneDayMs;
  });

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER:
        return <Scanner onScanComplete={handleScanComplete} customLocation={manualLocation} />;
      case ViewState.LEADERBOARD:
        return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE:
        return <Dashboard user={currentUser} logbook={logbook} onLogout={handleLogout} />;
      case ViewState.MAP:
        return (
          <InteractiveMap 
            items={mapItems} 
            isExternalSelectionMode={isSelectingLocation}
            onViewWaypointInfo={() => setView(ViewState.WAYPOINT_INFO)}
            onLocationSelect={(location) => {
              setManualLocation(location);
              setIsSelectingLocation(false);
              setView(ViewState.SCANNER);
            }}
            onSelectionCancel={() => {
              setIsSelectingLocation(false);
            }}
          />
        );
      case ViewState.ACHIEVEMENTS:
        return <Achievements history={logbook} badges={currentUser.badges} />;
      case ViewState.WAYPOINT_INFO:
        return <WaypointInfo onBack={() => setView(ViewState.MAP)} />;
      case ViewState.ANIMALS_LIST:
        return <AnimalsList items={logbook} />;
      default:
        return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-stone-50 text-stone-900 font-sans overflow-hidden">

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative z-0">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      {view !== ViewState.WAYPOINT_INFO && (
        <nav className="bg-white border-t border-stone-200 pb-safe shadow-[0_-5px_15px_rgba(0,0,0,0.02)] relative z-50">
          <div className="flex justify-between items-center h-16 max-w-lg mx-auto px-2">

            <button 
              onClick={() => {
                setView(ViewState.LEADERBOARD);
                setManualLocation(undefined);
                setIsSelectingLocation(false);
              }}
