import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeImage = async (base64Image: string): Promise<AnalysisResult> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          {
            text: `Analyze this image to identify the piece of rubbish or waste present.
            Provide a strict JSON response.
            Determine if it is recyclable and what material it is primarily made of.

            Scoring Rules:
            - Recyclable plastic/paper/metal: 10 points.
            - Hazardous/E-waste properly identified: 20 points.
            - Non-recyclable waste: 5 points (for cleaning it up).

            Provide clear disposal advice (e.g., 'Blue bin', 'Yellow bin', 'Special collection').
            Provide a short statement on the environmental impact of this item if left as litter.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            itemName: { type: Type.STRING },
            material: { type: Type.STRING },
            category: { type: Type.STRING, enum: ["Plastic", "Paper", "Metal", "Glass", "E-Waste", "Organic", "Hazardous", "Other"] },
            isRecyclable: { type: Type.BOOLEAN },
            disposalAdvice: { type: Type.STRING },
            environmentalImpact: { type: Type.STRING },
            estimatedPoints: { type: Type.INTEGER },
            funFact: { type: Type.STRING }
          },
          required: ["itemName", "material", "category", "isRecyclable", "disposalAdvice", "environmentalImpact", "estimatedPoints", "funFact"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text from Gemini");

    const result = JSON.parse(text) as AnalysisResult;
    return result;
  } catch (error) {
    console.error("Gemini Recycling Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, CheckCircle, XCircle, Loader2, MapPin, Recycle, Trash2, Plus, Minus, Info } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult, RecycleEntry } from '../types';

interface ScannerProps {
  onScanComplete: (item: RecycleEntry) => void;
  customLocation?: { lat: number; lng: number };
}

const generateSignature = (str: string): string => {
  let hash = 0;
  if (str.length === 0) return hash.toString();
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return hash.toString();
};

type ScanStep = 'SCAN_WASTE' | 'ANALYZING' | 'REVIEW_RESULT';

export const Scanner: React.FC<ScannerProps> = ({ onScanComplete, customLocation }) => {
  const [step, setStep] = useState<ScanStep>('SCAN_WASTE');
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [itemImageUrl, setItemImageUrl] = useState<string | null>(null);
  const [imageSignature, setImageSignature] = useState<string | null>(null);
  const [location, setLocation] = useState<{lat: number, lng: number} | undefined>(customLocation);
  const [quantity, setQuantity] = useState<number>(1);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (customLocation) {
      setLocation(customLocation);
    } else if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        null,
        { enableHighAccuracy: true }
      );
    }
  }, [customLocation]);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const objectUrl = URL.createObjectURL(file);
    setItemImageUrl(objectUrl);
    setStep('ANALYZING');

    try {
      const base64Data = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
      });

      setImageSignature(generateSignature(base64Data));
      const analysis = await analyzeImage(base64Data);
      setResult(analysis);
      setStep('REVIEW_RESULT');
    } catch (err) {
      setError("Identification failed. Please ensure the rubbish is clearly visible.");
      setStep('SCAN_WASTE');
    }
  };

  const handleFinalSubmit = () => {
    if (result && itemImageUrl) {
      const newEntry: RecycleEntry = {
        id: Date.now().toString(),
        itemName: result.itemName,
        material: result.material,
        category: result.category,
        isRecyclable: result.isRecyclable,
        points: result.estimatedPoints,
        timestamp: Date.now(),
        imageUrl: itemImageUrl,
        disposalAdvice: result.disposalAdvice,
        environmentalImpact: result.environmentalImpact,
        location: location,
        imageSignature: imageSignature || undefined,
        quantity: quantity
      };
      onScanComplete(newEntry);
      setStep('SCAN_WASTE');
    }
  };

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4">
      {step === 'SCAN_WASTE' && (
        <div className="flex flex-col items-center justify-center flex-1 space-y-8">
           <div className="text-center space-y-2">
             <h2 className="text-2xl font-bold text-emerald-900">Identify Rubbish</h2>
             <p className="text-sm text-stone-500">Scan waste to earn Eco-Points</p>
           </div>

           <label className="relative cursor-pointer group">
              <div className="absolute -inset-4 bg-emerald-400/20 rounded-full blur-xl group-hover:bg-emerald-400/30 transition-all duration-500"></div>
              <div className="relative w-48 h-48 bg-white rounded-full border-8 border-emerald-50 shadow-2xl flex flex-col items-center justify-center space-y-2 active:scale-95 transition-transform">
                <Recycle className="w-12 h-12 text-emerald-600" />
                <span className="text-sm font-bold text-emerald-700">Spot & Scan</span>
              </div>
              <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFileChange} />
           </label>

           {customLocation && (
             <div className="flex items-center space-x-2 px-4 py-2 bg-emerald-50 text-emerald-700 rounded-full text-xs font-bold border border-emerald-100">
                <MapPin size={14} />
                <span>Pinned Location Active</span>
             </div>
           )}
        </div>
      )}

      {step === 'ANALYZING' && (
        <div className="flex flex-col items-center justify-center flex-1 space-y-6">
          <div className="relative w-64 h-64 rounded-3xl overflow-hidden border-4 border-white shadow-2xl">
            <img src={itemImageUrl!} className="w-full h-full object-cover blur-sm" />
            <div className="absolute inset-0 bg-emerald-900/20 flex items-center justify-center">
              <Loader2 className="w-12 h-12 text-white animate-spin" />
            </div>
          </div>
          <div className="text-center">
            <p className="text-emerald-800 font-bold animate-pulse">Analyzing Material Composition...</p>
            <p className="text-stone-400 text-xs mt-1">Consulting global recycling standards</p>
          </div>
        </div>
      )}

      {step === 'REVIEW_RESULT' && result && (
        <div className="flex flex-col flex-1 animate-in slide-in-from-bottom-8 duration-500">
          <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-emerald-100 flex-1 flex flex-col">
            <div className="relative h-48">
              <img src={itemImageUrl!} className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent flex flex-col justify-end p-5">
                <h3 className="text-white text-2xl font-bold">{result.itemName}</h3>
                <p className="text-emerald-200 text-sm font-medium">{result.material}</p>
              </div>
            </div>

            <div className="p-6 space-y-4 flex-1 overflow-y-auto">
              <div className="flex items-center justify-between">
                <div className={`px-4 py-1.5 rounded-full flex items-center space-x-2 ${result.isRecyclable ? 'bg-emerald-100 text-emerald-800' : 'bg-red-50 text-red-700'}`}>
                  {result.isRecyclable ? <Recycle size={18} /> : <Trash2 size={18} />}
                  <span className="font-bold text-sm">{result.category}</span>
                </div>
                <div className="text-emerald-600 font-bold text-lg">+{result.estimatedPoints} pts</div>
              </div>

              <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
                <h4 className="text-xs font-bold text-emerald-700 uppercase mb-1">Disposal Instruction</h4>
                <p className="text-sm text-emerald-900 font-medium">{result.disposalAdvice}</p>
              </div>

              <div className="flex items-start space-x-3 p-4 bg-stone-50 rounded-2xl border border-stone-100">
                <Info className="w-5 h-5 text-stone-400 flex-shrink-0 mt-0.5" />
                <div>
                  <h4 className="text-xs font-bold text-stone-500 uppercase mb-1">Environmental Impact</h4>
