                <div className="flex items-center space-x-4 bg-stone-100 rounded-xl p-1">
                  <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className="p-2 bg-white rounded-lg shadow-sm"><Minus size={16}/></button>
                  <span className="font-bold text-emerald-800 w-4 text-center">{quantity}</span>
                  <button onClick={() => setQuantity(q => q + 1)} className="p-2 bg-white rounded-lg shadow-sm"><Plus size={16}/></button>
                </div>
              </div>
            </div>

            <div className="p-4 bg-stone-50 border-t border-stone-100 flex space-x-3">
