];

export const AnimalsList: React.FC<WasteGuideProps> = ({ items }) => {
  const foundMap = new Map<string, RecycleEntry>();

  items.forEach(item => {
    const matched = COMMON_RECYCLABLES.find(s => 
      item.itemName.toLowerCase().includes(s.name.toLowerCase()) || 
      s.name.toLowerCase().includes(item.itemName.toLowerCase())
    );
    if (matched && !foundMap.has(matched.name)) {
      foundMap.set(matched.name, item);
    }
  });

  const renderCard = (target: typeof COMMON_RECYCLABLES[0]) => {
    const userEntry = foundMap.get(target.name);
    const isFound = !!userEntry;
    const displayImg = isFound ? userEntry.imageUrl : target.image;

    return (
      <div className={`rounded-2xl overflow-hidden shadow-sm border transition-all ${isFound ? 'bg-white border-emerald-100' : 'bg-stone-50 border-stone-200'}`}>
        <div className="h-32 w-full relative overflow-hidden bg-stone-200">
           <img 
              src={displayImg} 
              className={`w-full h-full object-cover transition-all duration-700 ${isFound ? '' : 'grayscale contrast-75 blur-[2px] opacity-40'}`} 
           />
           {!isFound && (
             <div className="absolute inset-0 flex items-center justify-center">
                <Lock className="text-stone-400 opacity-50" size={24} />
             </div>
           )}
           <div className="absolute top-2 right-2">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${isFound ? 'bg-emerald-600 text-white' : 'bg-stone-400 text-white'}`}>
                {target.category}
              </span>
           </div>
        </div>
        <div className="p-3">
          <h3 className={`font-bold text-sm ${isFound ? 'text-emerald-900' : 'text-stone-400'}`}>{target.name}</h3>
          <p className="text-[10px] text-stone-500 font-medium">{target.material}</p>
          <div className="mt-3 flex items-center justify-between">
             {isFound ? (
               <span className="text-[10px] bg-emerald-50 text-emerald-600 px-2 py-0.5 rounded font-bold">RECYCLED</span>
             ) : (
               <span className="text-[10px] bg-stone-100 text-stone-400 px-2 py-0.5 rounded font-bold">LOCKED</span>
             )}
             {isFound ? <CheckCircle2 className="text-emerald-500" size={14} /> : <Circle className="text-stone-300" size={14} />}
          </div>
        </div>
      </div>
    );
  };

  const foundCount = foundMap.size;
  const progress = (foundCount / COMMON_RECYCLABLES.length) * 100;

  return (
    <div className="flex flex-col h-full max-w-md mx-auto p-4 overflow-y-auto no-scrollbar pb-24">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-emerald-900">Eco-Guide</h2>
        <div className="flex justify-between text-xs text-stone-500 mb-2 font-bold">
           <span>Waste Collection Progress</span>
           <span className="text-emerald-600">{foundCount} / {COMMON_RECYCLABLES.length}</span>
        </div>
        <div className="h-2 w-full bg-stone-100 rounded-full overflow-hidden border border-stone-200">
           <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${progress}%` }} />
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        {COMMON_RECYCLABLES.map((item, idx) => (
          <div key={idx}>{renderCard(item)}</div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { Achievements, ACHIEVEMENT_RULES } from './components/Achievements';
import { WaypointInfo } from './components/WaypointInfo';
import { AnimalsList } from './components/AnimalsList';
import { User, RecycleEntry, ViewState } from './types';
import { Scan, TrendingUp, User as UserIcon, Map as MapIcon, BookOpen } from 'lucide-react';

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [logbook, setLogbook] = useState<RecycleEntry[]>([]);
  const [manualLocation, setManualLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  const [isSelectingLocation, setIsSelectingLocation] = useState(false);

  useEffect(() => {
    if (currentUser) {
      setUsers(prev => {
        const others = prev.filter(u => u.id !== currentUser.id);
        return [...others, currentUser];
      });
    }
  }, [currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
  };

  const handleScanComplete = (entry: RecycleEntry) => {
    if (!currentUser) return;
    const updatedLogbook = [...logbook, entry];
    setLogbook(updatedLogbook);
    setManualLocation(undefined);

    setCurrentUser(prev => prev ? ({
      ...prev,
      totalPoints: prev.totalPoints + entry.points,
      sightingsLogged: prev.sightingsLogged + 1,
    }) : null);

    setView(ViewState.ANIMALS_LIST);
  };

  if (!isAuthenticated || !currentUser) return <Login onLogin={handleLogin} />;

  const renderContent = () => {
    switch (view) {
      case ViewState.SCANNER: return <Scanner onScanComplete={handleScanComplete} customLocation={manualLocation} />;
      case ViewState.LEADERBOARD: return <Leaderboard users={users} currentUser={currentUser} />;
      case ViewState.PROFILE: return <Dashboard user={currentUser} logbook={logbook} onLogout={() => setIsAuthenticated(false)} />;
      case ViewState.MAP: return (
        <InteractiveMap 
          items={logbook as any} 
          isExternalSelectionMode={isSelectingLocation}
          onViewWaypointInfo={() => setView(ViewState.WAYPOINT_INFO)}
          onLocationSelect={(loc) => {
            setManualLocation(loc);
            setIsSelectingLocation(false);
            setView(ViewState.SCANNER);
          }}
          onSelectionCancel={() => setIsSelectingLocation(false)}
        />
      );
      case ViewState.WAYPOINT_INFO: return <WaypointInfo onBack={() => setView(ViewState.MAP)} />;
      case ViewState.ANIMALS_LIST: return <AnimalsList items={logbook} />;
      default: return <Scanner onScanComplete={handleScanComplete} />;
    }
  };

  return (
    <div className="flex flex-col h-screen bg-stone-50 text-stone-900 font-sans overflow-hidden">
      <main className="flex-1 overflow-hidden relative">{renderContent()}</main>
      <nav className="bg-white border-t border-stone-200 h-16 flex justify-around items-center px-4 relative z-50">
        <button onClick={() => setView(ViewState.LEADERBOARD)} className={`flex flex-col items-center ${view === ViewState.LEADERBOARD ? 'text-emerald-600' : 'text-stone-400'}`}>
          <TrendingUp size={20} />
          <span className="text-[10px] font-bold">Ranks</span>
        </button>
        <button onClick={() => setView(ViewState.ANIMALS_LIST)} className={`flex flex-col items-center ${view === ViewState.ANIMALS_LIST ? 'text-emerald-600' : 'text-stone-400'}`}>
          <BookOpen size={20} />
          <span className="text-[10px] font-bold">Guide</span>
        </button>
        <button 
          onClick={() => { setView(ViewState.MAP); setIsSelectingLocation(true); }}
          className="flex flex-col items-center -mt-6"
        >
          <div className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-all ${isSelectingLocation ? 'bg-emerald-600 scale-110' : 'bg-stone-800'}`}>
            <Scan className="text-white" />
          </div>
          <span className="text-[10px] font-bold mt-1 text-stone-400">Spot</span>
        </button>
        <button onClick={() => { setView(ViewState.MAP); setIsSelectingLocation(false); }} className={`flex flex-col items-center ${view === ViewState.MAP && !isSelectingLocation ? 'text-emerald-600' : 'text-stone-400'}`}>
          <MapIcon size={20} />
          <span className="text-[10px] font-bold">Map</span>
        </button>
        <button onClick={() => setView(ViewState.PROFILE)} className={`flex flex-col items-center ${view === ViewState.PROFILE ? 'text-emerald-600' : 'text-stone-400'}`}>
          <UserIcon size={20} />
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
}

