                 onClick={handleCaptureLocation}
                 className="flex items-center space-x-2 bg-emerald-600 text-white px-8 py-3.5 rounded-full shadow-xl hover:bg-emerald-700 transition font-bold animate-in zoom-in duration-200 border-2 border-white/20"
