import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeImage = async (base64Image: string): Promise<AnalysisResult> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          {
            text: `Analyze this image to identify the piece of rubbish or waste.
            Provide a strict JSON response.
            Determine the material (e.g., PET Plastic, Aluminum, Cardboard) and category.

            Scoring Rules:
            - Recyclable materials: 10-15 points.
            - Hazardous/E-waste: 25 points.
            - Trash (non-recyclable): 5 points (for proper disposal).

            Provide specific disposal advice (e.g., 'Blue Bin', 'Recycling Center') and a short environmental impact fact.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            itemName: { type: Type.STRING },
            material: { type: Type.STRING },
            category: { type: Type.STRING, enum: ["Plastic", "Paper", "Metal", "Glass", "E-Waste", "Organic", "Hazardous", "Other"] },
            isRecyclable: { type: Type.BOOLEAN },
            disposalAdvice: { type: Type.STRING },
            environmentalImpact: { type: Type.STRING },
            estimatedPoints: { type: Type.INTEGER },
            funFact: { type: Type.STRING }
          },
          required: ["itemName", "material", "category", "isRecyclable", "disposalAdvice", "environmentalImpact", "estimatedPoints", "funFact"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response text from Gemini");

    const result = JSON.parse(text) as AnalysisResult;
    return result;
  } catch (error) {
    console.error("Recycling Analysis Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState } from 'react';
import * as L from 'leaflet';
import { RecycleEntry } from '../types';
import { MapPin, Crosshair, X, Check, Navigation } from 'lucide-react';

interface InteractiveMapProps {
  items: RecycleEntry[];
  isExternalSelectionMode: boolean;
  onViewWaypointInfo: () => void;
  onLocationSelect: (location: { lat: number; lng: number }) => void;
  onSelectionCancel: () => void;
}

export const InteractiveMap: React.FC<InteractiveMapProps> = ({ 
  items, 
  isExternalSelectionMode,
  onViewWaypointInfo, 
  onLocationSelect,
  onSelectionCancel
}) => {
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);
  const onViewWaypointInfoRef = useRef(onViewWaypointInfo);
  const [internalSelectionMode, setInternalSelectionMode] = useState(false);

  useEffect(() => {
    setInternalSelectionMode(isExternalSelectionMode);
  }, [isExternalSelectionMode]);

  useEffect(() => {
    onViewWaypointInfoRef.current = onViewWaypointInfo;
  }, [onViewWaypointInfo]);

  const defaultCenter: [number, number] = [22.274056, 114.175944];

  useEffect(() => {
    if (!mapContainerRef.current) return;

    if (!mapInstanceRef.current) {
      mapInstanceRef.current = L.map(mapContainerRef.current, {
        zoomControl: false,
        attributionControl: false,
        minZoom: 16,
        maxZoom: 19
      }).setView(defaultCenter, 19); 

      L.tileLayer('https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}', {
        attribution: 'Tiles &copy; Esri',
        maxZoom: 19
      }).addTo(mapInstanceRef.current);
    }

    const map = mapInstanceRef.current;

    map.eachLayer((layer) => {
      if (layer instanceof L.Marker) {
        map.removeLayer(layer);
      }
    });

    // Central Waypoint
    const waypointIconHtml = `
      <div class="relative flex items-center justify-center w-12 h-12">
         <div class="absolute w-12 h-12 bg-emerald-500 rounded-full opacity-20 animate-pulse"></div>
         <div class="relative w-10 h-10 bg-emerald-600 rounded-full border-2 border-white shadow-xl flex items-center justify-center text-white z-10">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg>
         </div>
      </div>
    `;

    const waypointIcon = L.divIcon({
        className: 'bg-transparent border-none',
        html: waypointIconHtml,
        iconSize: [48, 48],
        iconAnchor: [24, 48]
    });

    L.marker(defaultCenter, { icon: waypointIcon }).addTo(map);

    // Items
    items.forEach(item => {
      if (!item.location) return;
      const iconHtml = `
        <div class="relative flex items-center justify-center w-8 h-8">
           <div class="relative w-8 h-8 bg-white rounded-full border-2 border-emerald-500 shadow-lg flex items-center justify-center text-emerald-600">
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg>
           </div>
        </div>
      `;
      const customIcon = L.divIcon({ html: iconHtml, className: 'bg-transparent border-none', iconSize: [32, 32] });
      L.marker([item.location.lat, item.location.lng], { icon: customIcon }).addTo(map);
    });

  }, [items]);

  const handleLocateMe = () => {
    if (navigator.geolocation && mapInstanceRef.current) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          mapInstanceRef.current?.flyTo([pos.coords.latitude, pos.coords.longitude], 19, {
            duration: 1.5
          });
        },
        (err) => alert("Could not access location. Please enable GPS."),
        { enableHighAccuracy: true }
      );
    }
  };

  const handleCaptureLocation = () => {
    if (mapInstanceRef.current) {
        const center = mapInstanceRef.current.getCenter();
        onLocationSelect({ lat: center.lat, lng: center.lng });
    }
  };

  return (
    <div className="flex flex-col h-full relative">
       {/* Selection Overlay */}
       {internalSelectionMode && (
         <div className="absolute inset-0 z-20 pointer-events-none flex flex-col items-center justify-center">
            <div className="text-emerald-500 drop-shadow-md bg-white/40 p-2 rounded-full backdrop-blur-sm border-2 border-emerald-500/50">
                <Crosshair size={32} />
            </div>
         </div>
       )}

       {/* Locate Me Button */}
       <button 
         onClick={handleLocateMe}
         className="absolute right-4 bottom-24 z-30 w-12 h-12 bg-white rounded-full shadow-lg border border-stone-200 flex items-center justify-center text-emerald-600 hover:bg-emerald-50 transition-all active:scale-90"
       >
          <Navigation size={22} className="fill-emerald-100" />
       </button>

       {/* Confirm Controls */}
       {internalSelectionMode && (
         <div className="absolute bottom-6 left-0 right-0 z-40 flex justify-center px-4 space-x-3 pointer-events-none">
            <button onClick={onSelectionCancel} className="pointer-events-auto w-12 h-12 bg-white rounded-full shadow-lg flex items-center justify-center text-stone-500 border border-stone-200"><X /></button>
            <button onClick={handleCaptureLocation} className="pointer-events-auto flex-1 max-w-[200px] h-12 bg-emerald-600 text-white rounded-full shadow-lg font-bold flex items-center justify-center space-x-2 border-2 border-white/20">
               <Check size={20} />
               <span>Snap Location</span>
            </button>
         </div>
       )}

       <div ref={mapContainerRef} className="flex-1 w-full bg-stone-200" />
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Camera, CheckCircle, Loader2, MapPin, Recycle, Trash2, Plus, Minus, Info } from 'lucide-react';
import { analyzeImage } from '../services/geminiService';
import { AnalysisResult, RecycleEntry } from '../types';

interface ScannerProps {
  onScanComplete: (item: RecycleEntry) => void;
  customLocation?: { lat: number; lng: number };
}

type ScanStep = 'SCAN' | 'ANALYZING' | 'RESULT';

export const Scanner: React.FC<ScannerProps> = ({ onScanComplete, customLocation }) => {
  const [step, setStep] = useState<ScanStep>('SCAN');
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [quantity, setQuantity] = useState(1);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const previewUrl = URL.createObjectURL(file);
    setImageUrl(previewUrl);
    setStep('ANALYZING');

    try {
      const base64 = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
      });
      const analysis = await analyzeImage(base64);
      setResult(analysis);
      setStep('RESULT');
    } catch (err) {
      setStep('SCAN');
      alert("Analysis failed. Try again with a clearer photo.");
    }
  };

  const handleSave = () => {
    if (result && imageUrl) {
      onScanComplete({
        id: Date.now().toString(),
        itemName: result.itemName,
        material: result.material,
        category: result.category,
        isRecyclable: result.isRecyclable,
        points: result.estimatedPoints,
        timestamp: Date.now(),
        imageUrl: imageUrl,
        disposalAdvice: result.disposalAdvice,
        environmentalImpact: result.environmentalImpact,
        location: customLocation,
        quantity: quantity
      });
      setStep('SCAN');
    }
  };

  return (
    <div className="flex flex-col h-full p-4 bg-emerald-50/30">
      {step === 'SCAN' && (
        <div className="flex-1 flex flex-col items-center justify-center space-y-8">
          <div className="text-center">
            <h2 className="text-2xl font-bold text-emerald-900">Check Your Waste</h2>
            <p className="text-stone-500 text-sm mt-1">Let AI guide your recycling journey</p>
          </div>
          <label className="w-48 h-48 bg-white rounded-full shadow-2xl border-8 border-emerald-100 flex flex-col items-center justify-center cursor-pointer active:scale-95 transition-transform">
            <Camera size={48} className="text-emerald-600 mb-2" />
            <span className="font-bold text-emerald-700">Scan Item</span>
            <input ref={fileInputRef} type="file" accept="image/*" capture="environment" className="hidden" onChange={handleFileChange} />
          </label>
          {customLocation && (
            <div className="flex items-center space-x-2 bg-emerald-100 px-4 py-2 rounded-full text-emerald-800 text-xs font-bold">
              <MapPin size={14} /> <span>Location Pinned</span>
            </div>
          )}
        </div>
      )}

      {step === 'ANALYZING' && (
        <div className="flex-1 flex flex-col items-center justify-center space-y-4">
          <div className="w-64 h-64 rounded-3xl overflow-hidden border-4 border-white shadow-xl">
             <img src={imageUrl!} className="w-full h-full object-cover blur-md" />
          </div>
          <div className="flex items-center space-x-3 text-emerald-800 font-bold">
             <Loader2 className="animate-spin" />
             <span>Identifying Materials...</span>
          </div>
        </div>
      )}

      {step === 'RESULT' && result && (
        <div className="flex-1 flex flex-col overflow-hidden bg-white rounded-3xl shadow-xl border border-emerald-100">
           <div className="h-48 relative">
              <img src={imageUrl!} className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent flex flex-col justify-end p-5">
                 <h3 className="text-white text-xl font-bold">{result.itemName}</h3>
                 <p className="text-emerald-300 text-sm">{result.material}</p>
              </div>
           </div>
           <div className="p-6 space-y-4 flex-1 overflow-y-auto">
              <div className="flex justify-between items-center">
                 <div className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-bold uppercase">{result.category}</div>
                 <div className="text-emerald-600 font-bold">+{result.estimatedPoints} pts</div>
              </div>
              <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
                 <h4 className="text-xs font-black text-emerald-700 uppercase mb-1">Disposal Advice</h4>
                 <p className="text-sm text-emerald-900 font-medium">{result.disposalAdvice}</p>
              </div>
              <div className="flex space-x-3 p-4 bg-stone-50 rounded-xl">
                 <Info size={20} className="text-stone-400 flex-shrink-0" />
                 <p className="text-xs text-stone-600 leading-relaxed">{result.environmentalImpact}</p>
              </div>
              <div className="flex items-center justify-between pt-4">
                 <span className="font-bold text-stone-600">Quantity</span>
                 <div className="flex items-center space-x-4 bg-stone-100 p-1 rounded-lg">
                    <button onClick={() => setQuantity(q => Math.max(1, q-1))} className="p-2 bg-white rounded shadow-sm"><Minus size={14}/></button>
                    <span className="font-bold w-4 text-center">{quantity}</span>
                    <button onClick={() => setQuantity(q => q+1)} className="p-2 bg-white rounded shadow-sm"><Plus size={14}/></button>
                 </div>
              </div>
           </div>
           <div className="p-4 bg-stone-50 flex space-x-3 border-t">
              <button onClick={() => setStep('SCAN')} className="flex-1 py-3 text-stone-500 font-bold">Discard</button>
              <button onClick={handleSave} className="flex-[2] py-3 bg-emerald-600 text-white font-bold rounded-xl shadow-lg">Log Recycle</button>
           </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { RecycleEntry } from '../types';
import { CheckCircle2, Circle, Lock, Package } from 'lucide-react';

interface WasteGuideProps {
  items: RecycleEntry[];
}

const ECO_CATEGORIES = [
  { name: "PET Bottle", material: "Plastic #1", category: "Plastic", placeholder: "https://images.unsplash.com/photo-1613946069412-38f7f1d3315d?w=300" },
  { name: "Aluminum Can", material: "Aluminum", category: "Metal", placeholder: "https://images.unsplash.com/photo-1594404322491-fa9d96603b8f?w=300" },
  { name: "Glass Jar", material: "Glass", category: "Glass", placeholder: "https://images.unsplash.com/photo-1536939459926-301728717817?w=300" },
  { name: "Cardboard Box", material: "Paper", category: "Paper", placeholder: "https://images.unsplash.com/photo-1589939705384-5185138a04b9?w=300" },
  { name: "Milk Carton", material: "Mixed", category: "Paper", placeholder: "https://images.unsplash.com/photo-1612467269151-547e1329c5fc?w=300" },
  { name: "Electronic Trash", material: "E-Waste", category: "E-Waste", placeholder: "https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=300" },
];

export const AnimalsList: React.FC<WasteGuideProps> = ({ items }) => {
  const foundMap = new Map<string, RecycleEntry>();
  items.forEach(item => {
    const match = ECO_CATEGORIES.find(c => item.itemName.toLowerCase().includes(c.name.toLowerCase()));
    if (match && !foundMap.has(match.name)) foundMap.set(match.name, item);
  });

  return (
    <div className="flex flex-col h-full p-4 overflow-y-auto no-scrollbar pb-24">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-emerald-900">Eco-Guide</h2>
        <p className="text-stone-500 text-sm">Discover and recycle all categories</p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        {ECO_CATEGORIES.map((cat, idx) => {
          const userEntry = foundMap.get(cat.name);
          const isFound = !!userEntry;
          return (
            <div key={idx} className={`rounded-2xl overflow-hidden border transition-all ${isFound ? 'bg-white border-emerald-100 shadow-sm' : 'bg-stone-50 border-stone-200 opacity-60'}`}>
              <div className="h-32 relative bg-stone-200">
                <img 
                  src={isFound ? userEntry.imageUrl : cat.placeholder} 
                  className={`w-full h-full object-cover ${isFound ? '' : 'grayscale contrast-125'}`} 
                />
                {!isFound && <div className="absolute inset-0 flex items-center justify-center"><Lock size={20} className="text-stone-400" /></div>}
              </div>
              <div className="p-3">
                <h4 className={`font-bold text-sm ${isFound ? 'text-emerald-900' : 'text-stone-400'}`}>{cat.name}</h4>
                <div className="mt-2 flex items-center justify-between">
                   <span className="text-[10px] text-stone-500 font-bold">{cat.material}</span>
                   {isFound ? <CheckCircle2 size={14} className="text-emerald-500" /> : <Circle size={14} className="text-stone-300" />}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Scanner } from './components/Scanner';
import { Leaderboard } from './components/Leaderboard';
import { Dashboard } from './components/Dashboard';
import { Login } from './components/Login';
import { InteractiveMap } from './components/InteractiveMap';
import { Achievements, ACHIEVEMENT_RULES } from './components/Achievements';
import { WaypointInfo } from './components/WaypointInfo';
import { AnimalsList } from './components/AnimalsList';
import { User, RecycleEntry, ViewState } from './types';
import { Scan, TrendingUp, User as UserIcon, Map as MapIcon, BookOpen } from 'lucide-react';

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [view, setView] = useState<ViewState>(ViewState.SCANNER);
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [logbook, setLogbook] = useState<RecycleEntry[]>([]);
  const [manualLocation, setManualLocation] = useState<{lat: number, lng: number} | undefined>(undefined);
  const [isSelectingLocation, setIsSelectingLocation] = useState(false);

  useEffect(() => {
    if (currentUser) {
      setUsers(prev => {
        const others = prev.filter(u => u.id !== currentUser.id);
        return [...others, currentUser];
      });
    }
  }, [currentUser]);

  const handleScanComplete = (entry: RecycleEntry) => {
    if (!currentUser) return;
    setLogbook(prev => [...prev, entry]);
    setCurrentUser(prev => prev ? ({
      ...prev,
      totalPoints: prev.totalPoints + entry.points,
      sightingsLogged: prev.sightingsLogged + 1,
    }) : null);
    setView(ViewState.ANIMALS_LIST);
    setManualLocation(undefined);
  };

  if (!isAuthenticated || !currentUser) return <Login onLogin={(u) => { setCurrentUser(u); setIsAuthenticated(true); }} />;

  return (
    <div className="flex flex-col h-screen bg-stone-50 text-stone-900 overflow-hidden">
      <main className="flex-1 relative overflow-hidden">
        {view === ViewState.SCANNER && <Scanner onScanComplete={handleScanComplete} customLocation={manualLocation} />}
        {view === ViewState.LEADERBOARD && <Leaderboard users={users} currentUser={currentUser} />}
        {view === ViewState.PROFILE && <Dashboard user={currentUser} logbook={logbook} onLogout={() => setIsAuthenticated(false)} />}
        {view === ViewState.ANIMALS_LIST && <AnimalsList items={logbook} />}
        {view === ViewState.MAP && (
          <InteractiveMap 
            items={logbook} 
            isExternalSelectionMode={isSelectingLocation}
            onViewWaypointInfo={() => {}} 
            onLocationSelect={(loc) => { setManualLocation(loc); setIsSelectingLocation(false); setView(ViewState.SCANNER); }}
            onSelectionCancel={() => setIsSelectingLocation(false)}
          />
        )}
      </main>

      <nav className="bg-white border-t border-stone-200 h-16 flex justify-around items-center relative z-50">
        <button onClick={() => setView(ViewState.LEADERBOARD)} className={`flex flex-col items-center ${view === ViewState.LEADERBOARD ? 'text-emerald-600' : 'text-stone-400'}`}>
          <TrendingUp size={20} /> <span className="text-[10px] font-bold">Ranks</span>
        </button>
        <button onClick={() => setView(ViewState.ANIMALS_LIST)} className={`flex flex-col items-center ${view === ViewState.ANIMALS_LIST ? 'text-emerald-600' : 'text-stone-400'}`}>
          <BookOpen size={20} /> <span className="text-[10px] font-bold">Guide</span>
        </button>
        <button onClick={() => { setView(ViewState.MAP); setIsSelectingLocation(true); }} className="flex flex-col items-center -mt-8">
          <div className={`w-14 h-14 rounded-full flex items-center justify-center shadow-lg transition-all ${isSelectingLocation ? 'bg-emerald-600 scale-110' : 'bg-stone-800'}`}>
            <Scan className="text-white" />
          </div>
          <span className="text-[10px] font-bold mt-1 text-emerald-800">Spot</span>
        </button>
        <button onClick={() => { setView(ViewState.MAP); setIsSelectingLocation(false); }} className={`flex flex-col items-center ${view === ViewState.MAP && !isSelectingLocation ? 'text-emerald-600' : 'text-stone-400'}`}>
          <MapIcon size={20} /> <span className="text-[10px] font-bold">Map</span>
        </button>
        <button onClick={() => setView(ViewState.PROFILE)} className={`flex flex-col items-center ${view === ViewState.PROFILE ? 'text-emerald-600' : 'text-stone-400'}`}>
          <UserIcon size={20} /> <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
}

